BEGIN;

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-bohr", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match Column I (Spectral series) with Column II (Lower energy level n₁):\n\nColumn I: (P) Lyman series, (Q) Balmer series, (R) Paschen series, (S) Brackett series\n\nColumn II: (1) n₁ = 3, (2) n₁ = 1, (3) n₁ = 4, (4) n₁ = 2", "explanation": "The spectral series of hydrogen are named after their discoverers and are defined by the lower energy level: Lyman series has n₁ = 1 (UV region), Balmer series has n₁ = 2 (visible region), Paschen series has n₁ = 3 (IR region), Brackett series has n₁ = 4 (IR region). Therefore: P→2, Q→4, R→1, S→3.", "correct_answer": "C", "concept_tags": ["spectral-series", "hydrogen-spectrum", "energy-transitions"], "payload": {"question_id": "cuet-phy-atom-bohr-15", "subtopic": "Bohr Model of Hydrogen Atom", "topic_name": "Bohr Model of Hydrogen Atom", "bloom_level": "remember", "options": [{"key": "A", "text": "P→1, Q→2, R→3, S→4", "is_correct": false}, {"key": "B", "text": "P→2, Q→1, R→4, S→3", "is_correct": false}, {"key": "C", "text": "P→2, Q→4, R→1, S→3", "is_correct": true}, {"key": "D", "text": "P→4, Q→2, R→3, S→1", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This option assigns P (Lyman) to n₁ = 3, but the Lyman series corresponds to transitions to n₁ = 1, the ground state.", "misconception": "Not knowing that Lyman series terminates at the ground state"}, {"option_key": "B", "hint": "This swaps the Balmer and Paschen series assignments. Balmer corresponds to n₁ = 2 (not 1) and Paschen to n₁ = 3 (not 4).", "misconception": "Confusing the order of spectral series"}, {"option_key": "D", "hint": "This assigns Lyman to n₁ = 4 and Brackett to n₁ = 1, which is reversed. Lyman is the first series (n₁ = 1) and Brackett is the fourth (n₁ = 4).", "misconception": "Reversing the order of spectral series"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-bohr", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match Column I (Physical quantity in Bohr model) with Column II (Dependence on principal quantum number n for hydrogen atom):\n\nColumn I: (P) Orbital radius, (Q) Electron speed, (R) Total energy, (S) Time period of revolution\n\nColumn II: (1) Proportional to n³, (2) Proportional to n², (3) Inversely proportional to n², (4) Inversely proportional to n", "explanation": "In the Bohr model for hydrogen (Z = 1): Orbital radius rₙ ∝ n² (P→2). Electron speed vₙ ∝ 1/n (Q→4). Total energy Eₙ = −13.6/n² ∝ −1/n², so |Eₙ| ∝ 1/n² (R→3). Time period Tₙ = 2πrₙ/vₙ ∝ n²/(1/n) = n³ (S→1). Therefore the correct matching is P→2, Q→4, R→3, S→1.", "correct_answer": "D", "concept_tags": ["bohr-model", "quantum-number-dependence", "orbital-properties"], "payload": {"question_id": "cuet-phy-atom-bohr-16", "subtopic": "Bohr Model of Hydrogen Atom", "topic_name": "Bohr Model of Hydrogen Atom", "bloom_level": "analyze", "options": [{"key": "A", "text": "P→2, Q→3, R→4, S→1", "is_correct": false}, {"key": "B", "text": "P→1, Q→4, R→3, S→2", "is_correct": false}, {"key": "C", "text": "P→2, Q→4, R→1, S→3", "is_correct": false}, {"key": "D", "text": "P→2, Q→4, R→3, S→1", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "This assigns Q (electron speed) to 1/n² and R (energy) to 1/n. Speed varies as 1/n, not 1/n², and energy magnitude varies as 1/n², not 1/n.", "misconception": "Swapping the n-dependence of speed and energy"}, {"option_key": "B", "hint": "This assigns P (radius) to n³ and S (time period) to n². Radius varies as n² and time period as n³, not the other way around.", "misconception": "Confusing the n-dependence of radius and time period"}, {"option_key": "C", "hint": "This assigns R (energy) to n³ and S (time period) to 1/n². Energy magnitude varies as 1/n² and time period as n³.", "misconception": "Incorrectly matching energy and time period dependencies"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-bohr", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "In Bohr''s model of the hydrogen atom, the frequency of radiation emitted when an electron jumps from a higher orbit to a lower orbit equals the difference in energy of the two orbits divided by Planck''s constant.", "explanation": "This is TRUE. According to Bohr''s frequency condition (third postulate), when an electron transitions from a higher energy level E₂ to a lower energy level E₁, a photon is emitted with frequency ν = (E₂ − E₁)/h, where h is Planck''s constant. This is a direct statement of energy conservation: the photon carries away the exact energy difference between the two levels.", "correct_answer": "A", "concept_tags": ["bohr-frequency-condition", "photon-emission", "energy-conservation"], "payload": {"question_id": "cuet-phy-atom-bohr-17", "subtopic": "Bohr Model of Hydrogen Atom", "topic_name": "Bohr Model of Hydrogen Atom", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The statement is a direct expression of Bohr''s third postulate: hν = E₂ − E₁, which gives ν = (E₂ − E₁)/h. This is a fundamental result.", "misconception": "Confusing Bohr''s frequency condition with some other relationship"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-bohr", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "In the Bohr model, the electron in a hydrogen atom can revolve in any orbit as long as its energy is negative.", "explanation": "This is FALSE. In the Bohr model, the electron cannot revolve in any arbitrary orbit. It can only exist in specific quantized orbits where the angular momentum is an integral multiple of h/2π (i.e., L = nh/2π where n = 1, 2, 3, ...). This quantization condition restricts the electron to only certain discrete orbits, not all orbits with negative energy.", "correct_answer": "B", "concept_tags": ["quantized-orbits", "bohr-postulates", "angular-momentum"], "payload": {"question_id": "cuet-phy-atom-bohr-18", "subtopic": "Bohr Model of Hydrogen Atom", "topic_name": "Bohr Model of Hydrogen Atom", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The key feature of Bohr''s model is quantization — the electron is restricted to specific orbits where L = nh/2π. A continuous range of orbits with negative energy would be the classical model, which Bohr rejected.", "misconception": "Confusing the classical model (continuous orbits) with Bohr''s quantized model"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-bohr", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "The maximum number of spectral lines that can be emitted when a hydrogen atom in the 5th excited state de-excites to the ground state is _____.", "explanation": "The 5th excited state corresponds to n = 6 (since the ground state is n = 1, the first excited state is n = 2, and so on). The number of spectral lines emitted when an atom de-excites from level n to the ground state is n(n−1)/2 = 6(6−1)/2 = 6 × 5/2 = 15. These arise from all possible downward transitions between levels 6, 5, 4, 3, 2, and 1.", "correct_answer": "C", "concept_tags": ["spectral-lines", "excited-state", "de-excitation"], "payload": {"question_id": "cuet-phy-atom-bohr-19", "subtopic": "Bohr Model of Hydrogen Atom", "topic_name": "Bohr Model of Hydrogen Atom", "bloom_level": "apply", "options": [{"key": "A", "text": "10", "is_correct": false}, {"key": "B", "text": "5", "is_correct": false}, {"key": "C", "text": "15", "is_correct": true}, {"key": "D", "text": "6", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "10 = 5(5−1)/2, which would apply if the atom were in the 4th excited state (n = 5). The 5th excited state is n = 6.", "misconception": "Confusing the excited state number with the principal quantum number (n = 5 is the 4th excited state, not the 5th)"}, {"option_key": "B", "hint": "5 would be the number of direct transitions from n = 6 to lower levels (6→5, 6→4, 6→3, 6→2, 6→1), ignoring intermediate transitions.", "misconception": "Counting only transitions from the highest level"}, {"option_key": "D", "hint": "6 = 4(4−1)/2, which applies to n = 4 (3rd excited state). The 5th excited state has n = 6.", "misconception": "Using the wrong principal quantum number"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-bohr", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "hard", "question_text": "A research team is studying a distant star''s atmosphere by analyzing its absorption spectrum. They observe a series of dark lines corresponding to the Balmer series of hydrogen. The wavelength of the line corresponding to the transition from n = 4 to n = 2 is measured to be 486.1 nm. Using the Rydberg formula, if the Rydberg constant R = 1.097 × 10⁷ m⁻¹, calculate the wavelength of the Balmer series limit (n = ∞ to n = 2) and identify its spectral region.", "explanation": "The Balmer series limit corresponds to the transition from n₂ = ∞ to n₁ = 2. Using the Rydberg formula: 1/λ = R(1/n₁² − 1/n₂²) = R(1/4 − 1/∞) = R/4. Therefore λ = 4/R = 4/(1.097 × 10⁷) = 3.646 × 10⁻⁷ m = 364.6 nm. This wavelength (364.6 nm) lies in the ultraviolet region of the electromagnetic spectrum, just below the visible violet limit (~380 nm). The Balmer series limit marks the shortest wavelength (highest energy) transition in the Balmer series.", "correct_answer": "D", "concept_tags": ["rydberg-formula", "balmer-series-limit", "spectral-analysis", "stellar-spectroscopy"], "payload": {"question_id": "cuet-phy-atom-bohr-20", "subtopic": "Bohr Model of Hydrogen Atom", "topic_name": "Bohr Model of Hydrogen Atom", "bloom_level": "evaluate", "options": [{"key": "A", "text": "656.3 nm, visible region", "is_correct": false}, {"key": "B", "text": "121.5 nm, ultraviolet region", "is_correct": false}, {"key": "C", "text": "820.4 nm, infrared region", "is_correct": false}, {"key": "D", "text": "364.6 nm, ultraviolet region", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "656.3 nm is the wavelength of the first Balmer line (Hα, n = 3 to n = 2), not the series limit. The series limit has the shortest wavelength in the series.", "misconception": "Confusing the first line of the Balmer series with the series limit"}, {"option_key": "B", "hint": "121.5 nm corresponds to the Lyman-α line (n = 2 to n = 1), not the Balmer series limit. This is in the far UV.", "misconception": "Confusing Lyman series transitions with Balmer series limit"}, {"option_key": "C", "hint": "820.4 nm lies in the infrared region. The Balmer series lies in the visible-to-near-UV region, with the series limit at 364.6 nm.", "misconception": "Using an incorrect formula or confusing with the Paschen series"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The Lyman series of hydrogen spectrum lies in the:", "explanation": "The Lyman series corresponds to transitions from higher energy levels (n = 2, 3, 4, ...) to n = 1 (ground state). The wavelengths of the Lyman series range from 912 A to 1216 A, which fall in the ultraviolet (UV) region of the electromagnetic spectrum.", "correct_answer": "A", "concept_tags": ["lyman-series", "ultraviolet-region", "hydrogen-spectrum"], "payload": {"question_id": "cuet-phy-atom-spectra-01", "subtopic": "Hydrogen Spectrum and Spectral Series", "topic_name": "Hydrogen Spectrum and Spectral Series", "bloom_level": "remember", "options": [{"key": "A", "text": "Ultraviolet region", "is_correct": true}, {"key": "B", "text": "Visible region", "is_correct": false}, {"key": "C", "text": "Infrared region", "is_correct": false}, {"key": "D", "text": "Microwave region", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The visible region corresponds to the Balmer series (transitions to n = 2), not the Lyman series.", "misconception": "Confusing Balmer and Lyman series regions"}, {"option_key": "C", "hint": "The infrared region corresponds to the Paschen, Brackett, and Pfund series, not the Lyman series.", "misconception": "Confusing Paschen and Lyman series regions"}, {"option_key": "D", "hint": "Microwave wavelengths are much longer than the Lyman series wavelengths. No hydrogen spectral series falls in the microwave region.", "misconception": null}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The ratio of the maximum wavelength to the minimum wavelength of the Balmer series of hydrogen is:", "explanation": "The maximum wavelength of the Balmer series corresponds to the first line (n = 3 to n = 2): 1/lambda_max = R(1/4 - 1/9) = R(5/36), so lambda_max = 36/(5R). The minimum wavelength (series limit) corresponds to n = infinity to n = 2: 1/lambda_min = R(1/4 - 0) = R/4, so lambda_min = 4/R. Ratio = lambda_max/lambda_min = (36/5R)/(4/R) = 36/(5 x 4) = 36/20 = 9/5.", "correct_answer": "C", "concept_tags": ["balmer-series", "wavelength-ratio", "series-limit", "first-line", "rydberg-formula"], "payload": {"question_id": "cuet-phy-atom-spectra-02", "subtopic": "Hydrogen Spectrum and Spectral Series", "topic_name": "Hydrogen Spectrum and Spectral Series", "bloom_level": "analyze", "options": [{"key": "A", "text": "4/3", "is_correct": false}, {"key": "B", "text": "5/4", "is_correct": false}, {"key": "C", "text": "9/5", "is_correct": true}, {"key": "D", "text": "27/5", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "4/3 is the ratio of quantum numbers (n = 4 to n = 3), not the ratio of wavelengths. The calculation requires the full Rydberg formula.", "misconception": "Using ratio of quantum numbers instead of the Rydberg formula"}, {"option_key": "B", "hint": "5/4 does not arise from any correct combination of the Rydberg terms for the Balmer series.", "misconception": null}, {"option_key": "D", "hint": "27/5 would result from an incorrect calculation. The correct ratio is lambda_max/lambda_min = (36/5R)/(4/R) = 9/5.", "misconception": "Arithmetic error in simplifying the ratio"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The first line of the Balmer series of hydrogen corresponds to the transition:", "explanation": "The Balmer series corresponds to transitions from higher levels to n = 2. The first line (longest wavelength, lowest energy) corresponds to the transition from the nearest higher level, i.e., n = 3 to n = 2. This line is called H-alpha and has a wavelength of 6563 A (red colour).", "correct_answer": "B", "concept_tags": ["balmer-series", "first-line", "h-alpha", "hydrogen-transitions"], "payload": {"question_id": "cuet-phy-atom-spectra-03", "subtopic": "Hydrogen Spectrum and Spectral Series", "topic_name": "Hydrogen Spectrum and Spectral Series", "bloom_level": "remember", "options": [{"key": "A", "text": "n = 2 to n = 1", "is_correct": false}, {"key": "B", "text": "n = 3 to n = 2", "is_correct": true}, {"key": "C", "text": "n = infinity to n = 2", "is_correct": false}, {"key": "D", "text": "n = 4 to n = 2", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The transition from n = 2 to n = 1 belongs to the Lyman series, not the Balmer series.", "misconception": "Confusing Lyman and Balmer series"}, {"option_key": "C", "hint": "The transition from n = infinity to n = 2 gives the series limit (shortest wavelength), not the first line of the Balmer series.", "misconception": "Confusing series limit with the first line"}, {"option_key": "D", "hint": "The transition from n = 4 to n = 2 gives the second line (H-beta) of the Balmer series, not the first line.", "misconception": "Incorrect ordering of spectral lines"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The energy of the hydrogen atom in the ground state is -13.6 eV. The energy of the hydrogen atom in the second excited state is:", "explanation": "The energy of the hydrogen atom in the nth level is given by E_n = -13.6/n^2 eV. The second excited state corresponds to n = 3 (ground state is n = 1, first excited state is n = 2, second excited state is n = 3). So E_3 = -13.6/3^2 = -13.6/9 = -1.51 eV.", "correct_answer": "D", "concept_tags": ["energy-levels", "hydrogen-atom", "second-excited-state"], "payload": {"question_id": "cuet-phy-atom-spectra-04", "subtopic": "Hydrogen Spectrum and Spectral Series", "topic_name": "Hydrogen Spectrum and Spectral Series", "bloom_level": "apply", "options": [{"key": "A", "text": "-13.6 eV", "is_correct": false}, {"key": "B", "text": "-3.4 eV", "is_correct": false}, {"key": "C", "text": "-0.85 eV", "is_correct": false}, {"key": "D", "text": "-1.51 eV", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "-13.6 eV is the ground state energy (n = 1), not the second excited state.", "misconception": null}, {"option_key": "B", "hint": "-3.4 eV corresponds to n = 2 (first excited state). The second excited state is n = 3, not n = 2.", "misconception": "Confusing first excited state with second excited state"}, {"option_key": "C", "hint": "-0.85 eV corresponds to n = 4 (third excited state). Remember: second excited state means n = 3.", "misconception": "Incorrect identification of quantum number for excited states"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The wavelength of the first line of the Lyman series of hydrogen is 1216 A. The wavelength of the second line of the Balmer series is:", "explanation": "For the first line of the Lyman series (n = 2 to n = 1): 1/lambda_L = R(1/1^2 - 1/2^2) = R(1 - 1/4) = 3R/4. So lambda_L = 4/(3R). For the second line of the Balmer series (n = 4 to n = 2): 1/lambda_B = R(1/2^2 - 1/4^2) = R(1/4 - 1/16) = R(3/16) = 3R/16. So lambda_B = 16/(3R). Taking the ratio: lambda_B/lambda_L = (16/3R)/(4/3R) = 16/4 = 4. Therefore lambda_B = 4 x 1216 = 4864 A.", "correct_answer": "B", "concept_tags": ["lyman-series", "balmer-series", "wavelength-ratio", "rydberg-formula"], "payload": {"question_id": "cuet-phy-atom-spectra-05", "subtopic": "Hydrogen Spectrum and Spectral Series", "topic_name": "Hydrogen Spectrum and Spectral Series", "bloom_level": "apply", "options": [{"key": "A", "text": "3648 A", "is_correct": false}, {"key": "B", "text": "4864 A", "is_correct": true}, {"key": "C", "text": "6568 A", "is_correct": false}, {"key": "D", "text": "1216 A", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "3648 A would correspond to a ratio of 3, but the correct wavelength ratio between the second Balmer line and the first Lyman line is 4.", "misconception": "Incorrect application of the Rydberg formula"}, {"option_key": "C", "hint": "6568 A is close to the first line of the Balmer series (H-alpha), not the second line.", "misconception": "Confusing first and second lines of Balmer series"}, {"option_key": "D", "hint": "1216 A is the given wavelength of the first Lyman line. The Balmer series lines have longer wavelengths since they involve lower energy transitions.", "misconception": null}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The ratio of the shortest wavelength of the Balmer series to the shortest wavelength of the Lyman series of hydrogen is:", "explanation": "The shortest wavelength (series limit) of any series corresponds to the transition from n = infinity. For the Lyman series limit: 1/lambda_L = R(1/1^2 - 0) = R, so lambda_L = 1/R. For the Balmer series limit: 1/lambda_B = R(1/2^2 - 0) = R/4, so lambda_B = 4/R. Ratio = lambda_B/lambda_L = (4/R)/(1/R) = 4.", "correct_answer": "C", "concept_tags": ["series-limit", "balmer-series", "lyman-series", "wavelength-ratio"], "payload": {"question_id": "cuet-phy-atom-spectra-06", "subtopic": "Hydrogen Spectrum and Spectral Series", "topic_name": "Hydrogen Spectrum and Spectral Series", "bloom_level": "apply", "options": [{"key": "A", "text": "1", "is_correct": false}, {"key": "B", "text": "2", "is_correct": false}, {"key": "C", "text": "4", "is_correct": true}, {"key": "D", "text": "1/4", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "A ratio of 1 would mean both series have the same shortest wavelength, which is incorrect since the Balmer series transitions involve less energy.", "misconception": null}, {"option_key": "B", "hint": "A ratio of 2 would correspond to the ratio of the quantum numbers, but the wavelength depends on 1/n^2, giving a ratio of n^2 = 2^2 = 4.", "misconception": "Using n instead of n^2 in the formula"}, {"option_key": "D", "hint": "1/4 would mean the Balmer series limit has a shorter wavelength than the Lyman series limit, which contradicts the fact that Lyman series photons have higher energy.", "misconception": "Inverting the ratio"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The excitation energy required to excite a hydrogen atom from the ground state to the first excited state is:", "explanation": "The excitation energy is the difference between the energy of the excited state and the ground state. E_1 = -13.6 eV (ground state, n = 1). E_2 = -13.6/4 = -3.4 eV (first excited state, n = 2). Excitation energy = E_2 - E_1 = -3.4 - (-13.6) = -3.4 + 13.6 = 10.2 eV.", "correct_answer": "A", "concept_tags": ["excitation-energy", "ground-state", "first-excited-state", "hydrogen-atom"], "payload": {"question_id": "cuet-phy-atom-spectra-07", "subtopic": "Hydrogen Spectrum and Spectral Series", "topic_name": "Hydrogen Spectrum and Spectral Series", "bloom_level": "apply", "options": [{"key": "A", "text": "10.2 eV", "is_correct": true}, {"key": "B", "text": "13.6 eV", "is_correct": false}, {"key": "C", "text": "3.4 eV", "is_correct": false}, {"key": "D", "text": "1.89 eV", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "13.6 eV is the ionization energy from the ground state (energy needed to completely remove the electron), not the excitation energy to the first excited state.", "misconception": "Confusing ionization energy with excitation energy"}, {"option_key": "C", "hint": "3.4 eV is the magnitude of the energy of the first excited state, not the energy required to reach it from the ground state.", "misconception": "Confusing energy of a state with the excitation energy"}, {"option_key": "D", "hint": "1.89 eV is the energy difference between n = 3 and n = 2 (corresponding to the first Balmer line), not the excitation energy from the ground state.", "misconception": null}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The ionization energy of the hydrogen atom from its second excited state is:", "explanation": "The second excited state corresponds to n = 3. The energy of this state is E_3 = -13.6/3^2 = -13.6/9 = -1.51 eV. The ionization energy is the energy required to remove the electron from this state to n = infinity (E = 0). So ionization energy = 0 - (-1.51) = 1.51 eV.", "correct_answer": "D", "concept_tags": ["ionization-energy", "second-excited-state", "hydrogen-atom"], "payload": {"question_id": "cuet-phy-atom-spectra-08", "subtopic": "Hydrogen Spectrum and Spectral Series", "topic_name": "Hydrogen Spectrum and Spectral Series", "bloom_level": "apply", "options": [{"key": "A", "text": "13.6 eV", "is_correct": false}, {"key": "B", "text": "3.4 eV", "is_correct": false}, {"key": "C", "text": "0.85 eV", "is_correct": false}, {"key": "D", "text": "1.51 eV", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "13.6 eV is the ionization energy from the ground state (n = 1), not from the second excited state (n = 3).", "misconception": "Not adjusting ionization energy for the starting level"}, {"option_key": "B", "hint": "3.4 eV is the ionization energy from the first excited state (n = 2), not the second excited state (n = 3).", "misconception": "Confusing first and second excited states"}, {"option_key": "C", "hint": "0.85 eV is the ionization energy from n = 4 (third excited state), not n = 3 (second excited state).", "misconception": "Using wrong quantum number for the second excited state"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The wavelength of the first line of the Lyman series of a hydrogen-like ion He+ is:", "explanation": "For hydrogen-like ions, 1/lambda = RZ^2(1/n1^2 - 1/n2^2). For the first line of the Lyman series of He+ (Z = 2): 1/lambda = R(2)^2(1/1^2 - 1/2^2) = 4R(3/4) = 3R. For hydrogen, the first Lyman line: 1/lambda_H = R(3/4), so lambda_H = 4/(3R). For He+: 1/lambda_He = 3R, so lambda_He = 1/(3R). Ratio: lambda_He/lambda_H = (1/3R)/(4/3R) = 1/4. Since lambda_H = 1216 A, lambda_He = 1216/4 = 304 A.", "correct_answer": "A", "concept_tags": ["hydrogen-like-ions", "helium-ion", "lyman-series", "rydberg-formula"], "payload": {"question_id": "cuet-phy-atom-spectra-09", "subtopic": "Hydrogen Spectrum and Spectral Series", "topic_name": "Hydrogen Spectrum and Spectral Series", "bloom_level": "apply", "options": [{"key": "A", "text": "304 A", "is_correct": true}, {"key": "B", "text": "608 A", "is_correct": false}, {"key": "C", "text": "1216 A", "is_correct": false}, {"key": "D", "text": "152 A", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "608 A would result from dividing the hydrogen wavelength by 2 (using Z instead of Z^2). The correct formula uses Z^2 = 4 as the scaling factor.", "misconception": "Using Z instead of Z^2 in the Rydberg formula for hydrogen-like ions"}, {"option_key": "C", "hint": "1216 A is the first Lyman line of hydrogen (Z = 1). For He+ (Z = 2), the wavelength is scaled down by Z^2 = 4.", "misconception": "Ignoring the Z^2 factor for hydrogen-like ions"}, {"option_key": "D", "hint": "152 A would result from dividing by Z^3 = 8 instead of Z^2 = 4.", "misconception": "Using incorrect power of Z"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The wavelength of the first line of the Balmer series of hydrogen is 6563 A. The wavelength of the first line of the Lyman series of the same atom is approximately:", "explanation": "For the first Balmer line (n = 3 to n = 2): 1/lambda_B = R(1/4 - 1/9) = R(5/36). For the first Lyman line (n = 2 to n = 1): 1/lambda_L = R(1 - 1/4) = R(3/4). Ratio: lambda_L/lambda_B = (5/36)/(3/4) = (5/36) x (4/3) = 20/108 = 5/27. Therefore lambda_L = (5/27) x 6563 = 32815/27 = 1215.4 A, which is approximately 1215 A.", "correct_answer": "B", "concept_tags": ["balmer-series", "lyman-series", "wavelength-ratio", "rydberg-formula"], "payload": {"question_id": "cuet-phy-atom-spectra-10", "subtopic": "Hydrogen Spectrum and Spectral Series", "topic_name": "Hydrogen Spectrum and Spectral Series", "bloom_level": "analyze", "options": [{"key": "A", "text": "912 A", "is_correct": false}, {"key": "B", "text": "1215 A", "is_correct": true}, {"key": "C", "text": "1640 A", "is_correct": false}, {"key": "D", "text": "3282 A", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "912 A is the series limit (shortest wavelength) of the Lyman series, not the first line.", "misconception": "Confusing the series limit with the first spectral line"}, {"option_key": "C", "hint": "This value does not correspond to any standard hydrogen spectral line. Check the ratio calculation using the Rydberg formula.", "misconception": null}, {"option_key": "D", "hint": "3282 A would be half of 6563, suggesting a simple halving, but the relationship between spectral lines requires the full Rydberg formula.", "misconception": "Assuming a simple integer ratio between different series"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A hydrogen atom in the ground state absorbs a photon of energy 12.75 eV. The number of different spectral lines that can be emitted when the atom returns to the ground state is:", "explanation": "The energy of the ground state is -13.6 eV. After absorbing 12.75 eV, the total energy becomes -13.6 + 12.75 = -0.85 eV. Using E_n = -13.6/n^2: -0.85 = -13.6/n^2, so n^2 = 13.6/0.85 = 16, giving n = 4. The atom is excited to n = 4. The number of possible spectral lines emitted when it de-excites is n(n-1)/2 = 4(3)/2 = 6.", "correct_answer": "C", "concept_tags": ["photon-absorption", "energy-levels", "spectral-lines-formula", "hydrogen-atom"], "payload": {"question_id": "cuet-phy-atom-spectra-11", "subtopic": "Hydrogen Spectrum and Spectral Series", "topic_name": "Hydrogen Spectrum and Spectral Series", "bloom_level": "analyze", "options": [{"key": "A", "text": "1", "is_correct": false}, {"key": "B", "text": "3", "is_correct": false}, {"key": "C", "text": "6", "is_correct": true}, {"key": "D", "text": "10", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "1 line would mean only a direct transition from the excited state to the ground state. But the atom can also de-excite through intermediate levels.", "misconception": "Considering only direct transitions to the ground state"}, {"option_key": "B", "hint": "3 would be the number of direct transitions from n = 4 (to n = 3, 2, 1), but transitions between intermediate levels (3->2, 3->1, 2->1) must also be counted.", "misconception": "Counting only transitions from the highest excited level"}, {"option_key": "D", "hint": "10 corresponds to n = 5 using the formula n(n-1)/2. First verify that the absorbed energy takes the atom to n = 4, not n = 5.", "misconception": "Incorrect calculation of the excited state quantum number"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Which of the following transitions in the hydrogen atom will emit a photon of the highest frequency?", "explanation": "The frequency of the emitted photon is proportional to the energy difference between the two levels. E_n = -13.6/n^2 eV. For n = 2 to n = 1: Delta E = -13.6(1/1 - 1/4) = -13.6 x 3/4 = 10.2 eV. For n = 6 to n = 5: Delta E = -13.6(1/25 - 1/36) = -13.6 x 11/900 = 0.166 eV. For n = 4 to n = 3: Delta E = -13.6(1/9 - 1/16) = -13.6 x 7/144 = 0.66 eV. For n = 3 to n = 2: Delta E = -13.6(1/4 - 1/9) = -13.6 x 5/36 = 1.89 eV. The transition n = 2 to n = 1 has the largest energy difference and hence the highest frequency.", "correct_answer": "D", "concept_tags": ["transition-energy", "photon-frequency", "energy-level-diagram"], "payload": {"question_id": "cuet-phy-atom-spectra-12", "subtopic": "Hydrogen Spectrum and Spectral Series", "topic_name": "Hydrogen Spectrum and Spectral Series", "bloom_level": "analyze", "options": [{"key": "A", "text": "n = 6 to n = 5", "is_correct": false}, {"key": "B", "text": "n = 4 to n = 3", "is_correct": false}, {"key": "C", "text": "n = 3 to n = 2", "is_correct": false}, {"key": "D", "text": "n = 2 to n = 1", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "The energy gap between n = 6 and n = 5 is very small (about 0.17 eV) as higher energy levels are closely spaced.", "misconception": "Assuming higher quantum numbers give higher energy transitions"}, {"option_key": "B", "hint": "The n = 4 to n = 3 transition releases only 0.66 eV, much less than n = 2 to n = 1 which releases 10.2 eV.", "misconception": null}, {"option_key": "C", "hint": "While n = 3 to n = 2 gives 1.89 eV, the n = 2 to n = 1 transition gives 10.2 eV, which is much larger.", "misconception": null}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): The Balmer series of hydrogen spectrum is the only series that has some lines in the visible region. Reason (R): The wavelengths of the Balmer series range from 3646 A to 6563 A, which partially overlaps with the visible spectrum (3800 A to 7800 A).", "explanation": "The assertion is correct. Among all hydrogen spectral series, only the Balmer series has wavelengths in the visible range. The Lyman series is entirely in the UV region, while the Paschen, Brackett, and Pfund series are all in the infrared region. The reason is also correct and correctly explains the assertion. The Balmer series wavelengths (3646 A to 6563 A) do overlap with the visible range, which is why some Balmer lines (like H-alpha at 6563 A, H-beta at 4861 A) are visible to the human eye.", "correct_answer": "A", "concept_tags": ["balmer-series", "visible-spectrum", "hydrogen-spectral-series"], "payload": {"question_id": "cuet-phy-atom-spectra-13", "subtopic": "Hydrogen Spectrum and Spectral Series", "topic_name": "Hydrogen Spectrum and Spectral Series", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The reason directly explains why Balmer lines are visible — their wavelength range overlaps with the visible spectrum. So R is indeed the correct explanation of A.", "misconception": "Failing to see the causal connection between the wavelength range and visibility"}, {"option_key": "C", "hint": "The reason provides accurate wavelength data for the Balmer series. The range 3646 A to 6563 A is correct (series limit to first line).", "misconception": null}, {"option_key": "D", "hint": "The assertion is correct — no other hydrogen series (Lyman, Paschen, etc.) falls in the visible range.", "misconception": null}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): The spectral lines of the Lyman series of hydrogen have shorter wavelengths than those of the Balmer series. Reason (R): In the Franck-Hertz experiment, electrons lose energy in discrete amounts when they collide with mercury atoms, confirming the existence of quantized energy levels.", "explanation": "The assertion is correct. The Lyman series (transitions to n = 1) involves larger energy differences than the Balmer series (transitions to n = 2), so Lyman series photons have higher energy and shorter wavelength. The reason is also correct — the Franck-Hertz experiment does confirm quantized energy levels. However, the reason is NOT the correct explanation of the assertion. The shorter wavelengths of the Lyman series are due to the larger energy gaps when transitioning to n = 1, not because of the Franck-Hertz experiment.", "correct_answer": "B", "concept_tags": ["lyman-series", "balmer-series", "franck-hertz-experiment", "quantized-energy-levels"], "payload": {"question_id": "cuet-phy-atom-spectra-14", "subtopic": "Hydrogen Spectrum and Spectral Series", "topic_name": "Hydrogen Spectrum and Spectral Series", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": true}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "While both statements are independently correct, the Franck-Hertz experiment explains quantized energy levels in general — it does not specifically explain why the Lyman series has shorter wavelengths than the Balmer series.", "misconception": "Assuming any correct physics statement about energy levels is the explanation for spectral wavelength differences"}, {"option_key": "C", "hint": "The reason is correct — the Franck-Hertz experiment is a well-known experiment that demonstrated quantized energy levels in atoms.", "misconception": "Not recognizing the Franck-Hertz experiment as a valid confirmation of energy quantization"}, {"option_key": "D", "hint": "The assertion is correct — Lyman series wavelengths (912-1216 A) are indeed shorter than Balmer series wavelengths (3646-6563 A).", "misconception": null}]}}]'::jsonb, 'deploy-2026-03-05-b10');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match the spectral series in Column I with the spectral region in Column II:\n\nColumn I:\nA. Lyman series\nB. Balmer series\nC. Paschen series\nD. Brackett series\n\nColumn II:\n1. Visible and near UV\n2. Ultraviolet\n3. Far infrared\n4. Near infrared", "explanation": "The Lyman series (transitions to n = 1) lies in the ultraviolet region (A-2). The Balmer series (transitions to n = 2) lies in the visible and near UV region (B-1). The Paschen series (transitions to n = 3) lies in the near infrared region (C-4). The Brackett series (transitions to n = 4) lies in the far infrared region (D-3).", "correct_answer": "D", "concept_tags": ["lyman-series", "balmer-series", "paschen-series", "brackett-series", "spectral-regions"], "payload": {"question_id": "cuet-phy-atom-spectra-15", "subtopic": "Hydrogen Spectrum and Spectral Series", "topic_name": "Hydrogen Spectrum and Spectral Series", "bloom_level": "remember", "options": [{"key": "A", "text": "A-2, B-1, C-3, D-4", "is_correct": false}, {"key": "B", "text": "A-2, B-4, C-1, D-3", "is_correct": false}, {"key": "C", "text": "A-1, B-2, C-4, D-3", "is_correct": false}, {"key": "D", "text": "A-2, B-1, C-4, D-3", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "This swaps C and D. Paschen series lies in the near infrared (C-4), and Brackett series lies in the far infrared (D-3), not the other way around.", "misconception": "Swapping Paschen and Brackett series spectral regions"}, {"option_key": "B", "hint": "This assigns the Balmer series to infrared, which is incorrect. The Balmer series falls in the visible/near UV region.", "misconception": "Incorrectly placing the Balmer series in the infrared region"}, {"option_key": "C", "hint": "This swaps A and B. The Lyman series is in the UV region (A-2), and the Balmer series is in the visible region (B-1).", "misconception": "Confusing Lyman and Balmer series regions"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match the transitions in Column I with their spectral series in Column II:\n\nColumn I:\nA. n = 5 to n = 2\nB. n = 4 to n = 1\nC. n = 7 to n = 3\nD. n = 6 to n = 4\n\nColumn II:\n1. Lyman series\n2. Balmer series\n3. Paschen series\n4. Brackett series", "explanation": "A spectral line belongs to a series determined by its lower energy level. n = 5 to n = 2: lower level is n = 2, so it belongs to the Balmer series (A-2). n = 4 to n = 1: lower level is n = 1, so it belongs to the Lyman series (B-1). n = 7 to n = 3: lower level is n = 3, so it belongs to the Paschen series (C-3). n = 6 to n = 4: lower level is n = 4, so it belongs to the Brackett series (D-4).", "correct_answer": "C", "concept_tags": ["spectral-series-identification", "electron-transitions", "lyman-balmer-paschen-brackett"], "payload": {"question_id": "cuet-phy-atom-spectra-16", "subtopic": "Hydrogen Spectrum and Spectral Series", "topic_name": "Hydrogen Spectrum and Spectral Series", "bloom_level": "analyze", "options": [{"key": "A", "text": "A-1, B-2, C-3, D-4", "is_correct": false}, {"key": "B", "text": "A-2, B-1, C-4, D-3", "is_correct": false}, {"key": "C", "text": "A-2, B-1, C-3, D-4", "is_correct": true}, {"key": "D", "text": "A-3, B-1, C-2, D-4", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This assigns A to the Lyman series. The transition n = 5 to n = 2 has a lower level of n = 2, which corresponds to the Balmer series, not Lyman.", "misconception": "Identifying the series by the upper quantum number instead of the lower one"}, {"option_key": "B", "hint": "This swaps C and D. The transition n = 7 to n = 3 ends at n = 3 (Paschen), and n = 6 to n = 4 ends at n = 4 (Brackett).", "misconception": "Confusing Paschen and Brackett series"}, {"option_key": "D", "hint": "This assigns A to Paschen (n = 3), but the transition n = 5 to n = 2 ends at n = 2, making it a Balmer series line.", "misconception": "Incorrectly identifying the lower quantum number of the transition"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The series limit (shortest wavelength) of the Lyman series of hydrogen corresponds to the ionization energy of 13.6 eV from the ground state.", "explanation": "This statement is true. The series limit of the Lyman series corresponds to the transition from n = infinity to n = 1. The energy of this photon is E = E_infinity - E_1 = 0 - (-13.6) = 13.6 eV, which is exactly the ionization energy of hydrogen from the ground state. The corresponding wavelength is 912 A.", "correct_answer": "A", "concept_tags": ["series-limit", "lyman-series", "ionization-energy", "hydrogen-atom"], "payload": {"question_id": "cuet-phy-atom-spectra-17", "subtopic": "Hydrogen Spectrum and Spectral Series", "topic_name": "Hydrogen Spectrum and Spectral Series", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The series limit of the Lyman series is the transition from n = infinity to n = 1, which releases exactly 13.6 eV — the ionization energy. The statement is true.", "misconception": "Not recognizing that the Lyman series limit equals the ionization energy from the ground state"}, {"option_key": "C", "hint": "This is a placeholder option and not a valid choice.", "misconception": null}, {"option_key": "D", "hint": "This is a placeholder option and not a valid choice.", "misconception": null}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The Paschen series of hydrogen spectrum lies in the visible region of the electromagnetic spectrum.", "explanation": "This statement is false. The Paschen series corresponds to transitions from higher energy levels to n = 3. The wavelengths of the Paschen series range from approximately 8204 A to 18750 A, which fall entirely in the infrared region of the electromagnetic spectrum, not the visible region (3800 A to 7800 A). Only the Balmer series has lines in the visible region.", "correct_answer": "B", "concept_tags": ["paschen-series", "infrared-region", "hydrogen-spectrum"], "payload": {"question_id": "cuet-phy-atom-spectra-18", "subtopic": "Hydrogen Spectrum and Spectral Series", "topic_name": "Hydrogen Spectrum and Spectral Series", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The Paschen series (transitions to n = 3) has wavelengths in the range 8204 A to 18750 A, which lies entirely in the infrared, not the visible region.", "misconception": "Confusing the spectral region of the Paschen series with the Balmer series"}, {"option_key": "C", "hint": "This is a placeholder option and not a valid choice.", "misconception": null}, {"option_key": "D", "hint": "This is a placeholder option and not a valid choice.", "misconception": null}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "The excitation potential required to excite a hydrogen atom from the ground state to the first excited state is _____ V.", "explanation": "The excitation energy from the ground state (n = 1) to the first excited state (n = 2) is: Delta E = E_2 - E_1 = (-13.6/4) - (-13.6) = -3.4 + 13.6 = 10.2 eV. The excitation potential is the potential difference through which an electron must be accelerated to gain this energy. Since the energy is 10.2 eV, the excitation potential is 10.2 V (because eV = eV, so V = 10.2 V).", "correct_answer": "C", "concept_tags": ["excitation-potential", "ground-state", "first-excited-state", "hydrogen-atom"], "payload": {"question_id": "cuet-phy-atom-spectra-19", "subtopic": "Hydrogen Spectrum and Spectral Series", "topic_name": "Hydrogen Spectrum and Spectral Series", "bloom_level": "apply", "options": [{"key": "A", "text": "13.6 V", "is_correct": false}, {"key": "B", "text": "3.4 V", "is_correct": false}, {"key": "C", "text": "10.2 V", "is_correct": true}, {"key": "D", "text": "12.1 V", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "13.6 V is the ionization potential from the ground state, not the excitation potential to the first excited state.", "misconception": "Confusing ionization potential with excitation potential"}, {"option_key": "B", "hint": "3.4 V corresponds to the magnitude of the energy of the first excited state (-3.4 eV), not the energy difference from the ground state.", "misconception": "Using the energy of the final state instead of the energy difference"}, {"option_key": "D", "hint": "12.1 V is the excitation potential to the third energy level (n = 3), not the first excited state (n = 2). E_3 - E_1 = -1.51 + 13.6 = 12.09 eV.", "misconception": "Confusing the second excited state with the first excited state"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "medium", "question_text": "In a laboratory, a student is studying the emission spectrum of hydrogen gas using a discharge tube. The student observes that when the gas is excited, electrons jump to higher energy levels and then fall back, emitting radiation. The student records that the electron transitions from the 5th energy level produce spectral lines belonging to different series.\n\nHow many spectral lines in the Balmer series can be produced from transitions originating at the 5th energy level?", "explanation": "The Balmer series consists of transitions where the lower energy level is n = 2. From the 5th energy level, the possible transitions to n = 2 are: 5->2, 4->2, and 3->2. However, the question asks specifically for lines originating from transitions that start at n = 5. The direct transitions from n = 5 that belong to the Balmer series is only 5->2 (one line). But electrons from n = 5 can also cascade: 5->4->2, 5->3->2, etc. The Balmer series lines that can appear when electrons de-excite from n = 5 are: 5->2, 4->2, and 3->2. That gives 3 lines in the Balmer series. These are the transitions ending at n = 2 from levels 3, 4, and 5.", "correct_answer": "B", "concept_tags": ["balmer-series", "spectral-lines", "electron-transitions", "emission-spectrum"], "payload": {"question_id": "cuet-phy-atom-spectra-20", "subtopic": "Hydrogen Spectrum and Spectral Series", "topic_name": "Hydrogen Spectrum and Spectral Series", "bloom_level": "apply", "options": [{"key": "A", "text": "1", "is_correct": false}, {"key": "B", "text": "3", "is_correct": true}, {"key": "C", "text": "6", "is_correct": false}, {"key": "D", "text": "10", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "1 would be the count if only the direct transition 5->2 is considered. But through cascading, intermediate levels (n = 3, 4) also emit Balmer lines when they transition to n = 2.", "misconception": "Counting only the direct transition from n = 5 to n = 2"}, {"option_key": "C", "hint": "6 is the total number of spectral lines from all series when an electron de-excites from n = 4 using n(n-1)/2. This question asks only about Balmer series lines from n = 5.", "misconception": "Calculating total spectral lines instead of just Balmer series lines"}, {"option_key": "D", "hint": "10 is the total number of spectral lines from all series when an electron de-excites from n = 5. The question asks only about Balmer series lines.", "misconception": "Using n(n-1)/2 formula without restricting to Balmer series"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "In alpha decay, the parent nucleus emits:", "explanation": "In alpha decay, the parent nucleus emits an alpha particle, which is a helium-4 nucleus (₂He⁴) consisting of 2 protons and 2 neutrons. As a result, the mass number A decreases by 4 and the atomic number Z decreases by 2. For example, ²³⁸U → ²³⁴Th + ⁴He.", "correct_answer": "A", "concept_tags": ["alpha-decay", "helium-nucleus", "mass-number", "atomic-number"], "payload": {"question_id": "cuet-phy-nuclei-decay-01", "subtopic": "Radioactive Decay", "topic_name": "Radioactive Decay", "bloom_level": "remember", "options": [{"key": "A", "text": "A helium nucleus (₂He⁴) with A decreasing by 4 and Z by 2", "is_correct": true}, {"key": "B", "text": "An electron and an antineutrino", "is_correct": false}, {"key": "C", "text": "A high-energy photon with no change in A or Z", "is_correct": false}, {"key": "D", "text": "A proton with A decreasing by 1 and Z by 1", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Emission of an electron and antineutrino describes beta-minus (β⁻) decay, not alpha decay.", "misconception": "Confusing alpha decay with beta-minus decay"}, {"option_key": "C", "hint": "Emission of a high-energy photon with no change in A or Z describes gamma decay, not alpha decay.", "misconception": "Confusing alpha decay with gamma decay"}, {"option_key": "D", "hint": "Proton emission is a rare decay mode. Alpha decay specifically involves emission of ₂He⁴, not a single proton.", "misconception": "Confusing alpha particle with a proton"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The SI unit of radioactive activity is:", "explanation": "The SI unit of radioactive activity (rate of disintegration) is the becquerel (Bq), where 1 Bq = 1 disintegration per second. The older unit curie (Ci) is defined as 1 Ci = 3.7 × 10¹⁰ disintegrations per second, which was originally based on the activity of 1 gram of Ra-226.", "correct_answer": "B", "concept_tags": ["activity", "becquerel", "curie", "SI-units"], "payload": {"question_id": "cuet-phy-nuclei-decay-02", "subtopic": "Radioactive Decay", "topic_name": "Radioactive Decay", "bloom_level": "remember", "options": [{"key": "A", "text": "Curie (Ci)", "is_correct": false}, {"key": "B", "text": "Becquerel (Bq)", "is_correct": true}, {"key": "C", "text": "Rutherford (Rd)", "is_correct": false}, {"key": "D", "text": "Gray (Gy)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Curie is a non-SI (older CGS) unit of activity. The SI unit is becquerel. 1 Ci = 3.7 × 10¹⁰ Bq.", "misconception": "Confusing SI unit with the older traditional unit of activity"}, {"option_key": "C", "hint": "Rutherford (1 Rd = 10⁶ disintegrations/s) is another non-SI unit and is rarely used in modern physics.", "misconception": "Confusing the rutherford unit with the SI unit"}, {"option_key": "D", "hint": "Gray (Gy) is the SI unit of absorbed radiation dose (energy per unit mass), not activity.", "misconception": "Confusing activity with absorbed dose"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The half-life of a radioactive substance is 20 minutes. The fraction of the original sample that remains after 1 hour is:", "explanation": "In 1 hour = 60 minutes, the number of half-lives n = 60/20 = 3. After n half-lives, the fraction remaining is (1/2)ⁿ = (1/2)³ = 1/8. So 1/8 of the original sample remains undecayed after 1 hour.", "correct_answer": "C", "concept_tags": ["half-life", "radioactive-decay", "fraction-remaining"], "payload": {"question_id": "cuet-phy-nuclei-decay-03", "subtopic": "Radioactive Decay", "topic_name": "Radioactive Decay", "bloom_level": "apply", "options": [{"key": "A", "text": "1/2", "is_correct": false}, {"key": "B", "text": "1/4", "is_correct": false}, {"key": "C", "text": "1/8", "is_correct": true}, {"key": "D", "text": "1/16", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "1/2 would remain after just one half-life (20 min), not after 60 min. Count the number of half-lives: 60/20 = 3.", "misconception": "Using only one half-life period instead of calculating the correct number"}, {"option_key": "B", "hint": "1/4 would remain after two half-lives (40 min). After 60 min, three half-lives have elapsed, giving (1/2)³ = 1/8.", "misconception": "Miscounting the number of half-lives"}, {"option_key": "D", "hint": "1/16 = (1/2)⁴ would require four half-lives (80 min), but only 60 min have elapsed (3 half-lives).", "misconception": "Incorrectly calculating the number of half-lives"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "In gamma decay, the emitted radiation is:", "explanation": "Gamma decay involves the emission of high-energy electromagnetic radiation (photons) from a nucleus in an excited state transitioning to a lower energy state. During gamma emission, there is no change in the mass number (A) or atomic number (Z) of the nucleus, as no nucleons are emitted or converted.", "correct_answer": "D", "concept_tags": ["gamma-decay", "electromagnetic-radiation", "isomeric-transition"], "payload": {"question_id": "cuet-phy-nuclei-decay-04", "subtopic": "Radioactive Decay", "topic_name": "Radioactive Decay", "bloom_level": "remember", "options": [{"key": "A", "text": "A stream of electrons", "is_correct": false}, {"key": "B", "text": "A stream of helium nuclei", "is_correct": false}, {"key": "C", "text": "A stream of neutrons", "is_correct": false}, {"key": "D", "text": "High-energy electromagnetic radiation (photons)", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Electrons are emitted in beta-minus (β⁻) decay, not gamma decay. Gamma rays are electromagnetic radiation.", "misconception": "Confusing gamma radiation with beta radiation"}, {"option_key": "B", "hint": "Helium nuclei are emitted in alpha decay, not gamma decay.", "misconception": "Confusing gamma decay with alpha decay"}, {"option_key": "C", "hint": "Neutrons are not emitted in gamma decay. Gamma decay involves no particle emission, only photon emission.", "misconception": "Confusing gamma emission with neutron emission"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The half-life of a radioactive element is T₁/₂. The mean life (τ) of the element is:", "explanation": "The decay constant λ = 0.693/T₁/₂. The mean life is τ = 1/λ = T₁/₂/0.693 = T₁/₂/ln2 ≈ 1.44 T₁/₂. The mean life is always greater than the half-life by a factor of 1/ln2 ≈ 1.44.", "correct_answer": "B", "concept_tags": ["mean-life", "half-life", "decay-constant", "relation"], "payload": {"question_id": "cuet-phy-nuclei-decay-05", "subtopic": "Radioactive Decay", "topic_name": "Radioactive Decay", "bloom_level": "understand", "options": [{"key": "A", "text": "0.693 T₁/₂", "is_correct": false}, {"key": "B", "text": "T₁/₂ / 0.693", "is_correct": true}, {"key": "C", "text": "T₁/₂ / 2", "is_correct": false}, {"key": "D", "text": "2 T₁/₂", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "0.693 T₁/₂ gives a value less than T₁/₂, but the mean life is always greater than the half-life. The relation is τ = T₁/₂ / 0.693.", "misconception": "Inverting the relation between mean life and half-life"}, {"option_key": "C", "hint": "T₁/₂/2 has no physical basis. The correct relation involves the natural logarithm of 2, i.e., τ = T₁/₂/ln2.", "misconception": "Guessing an arbitrary simple fraction"}, {"option_key": "D", "hint": "2T₁/₂ is incorrect. The correct factor is 1/ln2 ≈ 1.44, not 2.", "misconception": "Approximating 1/ln2 as 2 instead of the correct value 1.44"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A radioactive sample has an initial activity of 800 Bq. If the half-life is 4 hours, the activity after 12 hours will be:", "explanation": "Number of half-lives = 12/4 = 3. Activity after n half-lives: A = A₀(1/2)ⁿ = 800 × (1/2)³ = 800 × 1/8 = 100 Bq. Activity decays exponentially just like the number of undecayed nuclei.", "correct_answer": "C", "concept_tags": ["activity", "half-life", "exponential-decay", "becquerel"], "payload": {"question_id": "cuet-phy-nuclei-decay-06", "subtopic": "Radioactive Decay", "topic_name": "Radioactive Decay", "bloom_level": "apply", "options": [{"key": "A", "text": "400 Bq", "is_correct": false}, {"key": "B", "text": "200 Bq", "is_correct": false}, {"key": "C", "text": "100 Bq", "is_correct": true}, {"key": "D", "text": "50 Bq", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "400 Bq = 800/2 is the activity after only 1 half-life (4 hours), not 12 hours.", "misconception": "Using only one half-life instead of calculating the correct number"}, {"option_key": "B", "hint": "200 Bq = 800/4 is the activity after 2 half-lives (8 hours), not 12 hours.", "misconception": "Miscounting the number of half-lives as 2 instead of 3"}, {"option_key": "D", "hint": "50 Bq = 800/16 would require 4 half-lives (16 hours), but only 12 hours have passed.", "misconception": "Overcounting the number of half-lives"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In β⁻ decay, a neutron inside the nucleus is converted into:", "explanation": "In beta-minus (β⁻) decay, a neutron inside the nucleus transforms into a proton, an electron (β⁻ particle), and an antineutrino: n → p + e⁻ + ν̄ₑ. The atomic number Z increases by 1 while the mass number A remains unchanged. The antineutrino carries away part of the energy, which explains the continuous energy spectrum of β⁻ particles.", "correct_answer": "A", "concept_tags": ["beta-minus-decay", "neutron-conversion", "antineutrino", "atomic-number"], "payload": {"question_id": "cuet-phy-nuclei-decay-07", "subtopic": "Radioactive Decay", "topic_name": "Radioactive Decay", "bloom_level": "understand", "options": [{"key": "A", "text": "A proton, an electron, and an antineutrino", "is_correct": true}, {"key": "B", "text": "A proton, an electron, and a neutrino", "is_correct": false}, {"key": "C", "text": "A proton, a positron, and a neutrino", "is_correct": false}, {"key": "D", "text": "A proton and an electron only", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "In β⁻ decay, the emitted lepton partner is an antineutrino (ν̄ₑ), not a neutrino. A neutrino is emitted in β⁺ decay.", "misconception": "Confusing neutrino with antineutrino in beta-minus decay"}, {"option_key": "C", "hint": "Positron emission occurs in β⁺ decay (p → n + e⁺ + νₑ), not in β⁻ decay.", "misconception": "Confusing beta-minus decay with beta-plus decay"}, {"option_key": "D", "hint": "A third particle (antineutrino) is essential to conserve energy, momentum, and lepton number. Its existence was postulated by Pauli to explain the continuous β-spectrum.", "misconception": "Ignoring the role of the antineutrino in beta decay"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In the nuclear fission of ²³⁵U by a slow neutron, the approximate energy released per fission is:", "explanation": "The fission of one ²³⁵U nucleus by a thermal (slow) neutron releases approximately 200 MeV of energy. This energy appears as kinetic energy of fission fragments (~165 MeV), kinetic energy of neutrons (~5 MeV), prompt gamma rays (~7 MeV), energy of fission products'' beta and gamma decay (~23 MeV), and neutrino energy (~12 MeV).", "correct_answer": "D", "concept_tags": ["nuclear-fission", "uranium-235", "energy-release", "slow-neutron"], "payload": {"question_id": "cuet-phy-nuclei-decay-08", "subtopic": "Radioactive Decay", "topic_name": "Radioactive Decay", "bloom_level": "remember", "options": [{"key": "A", "text": "2 MeV", "is_correct": false}, {"key": "B", "text": "20 MeV", "is_correct": false}, {"key": "C", "text": "2000 MeV", "is_correct": false}, {"key": "D", "text": "200 MeV", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "2 MeV is far too small. This is roughly the energy of a single gamma ray photon, not the total fission energy.", "misconception": "Underestimating fission energy by two orders of magnitude"}, {"option_key": "B", "hint": "20 MeV is the typical energy released in a single alpha decay, not fission. Fission releases about 10 times more energy.", "misconception": "Confusing fission energy with alpha decay energy"}, {"option_key": "C", "hint": "2000 MeV is ten times the actual fission energy. The binding energy per nucleon difference accounts for about 200 MeV.", "misconception": "Overestimating fission energy by an order of magnitude"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The decay constant of a radioactive substance is 0.0231 per minute. Its half-life is approximately:", "explanation": "Using T₁/₂ = 0.693/λ = 0.693/0.0231 = 30 minutes. The half-life and decay constant are inversely related through the factor ln2 = 0.693.", "correct_answer": "C", "concept_tags": ["decay-constant", "half-life", "radioactive-decay-law"], "payload": {"question_id": "cuet-phy-nuclei-decay-09", "subtopic": "Radioactive Decay", "topic_name": "Radioactive Decay", "bloom_level": "apply", "options": [{"key": "A", "text": "10 minutes", "is_correct": false}, {"key": "B", "text": "20 minutes", "is_correct": false}, {"key": "C", "text": "30 minutes", "is_correct": true}, {"key": "D", "text": "45 minutes", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "T₁/₂ = 0.693/0.0231 = 30 min, not 10 min. Check your arithmetic: 0.693/0.0231 ≠ 10.", "misconception": "Arithmetic error in division"}, {"option_key": "B", "hint": "20 minutes would require λ = 0.693/20 = 0.0347 per min, which does not match the given λ = 0.0231.", "misconception": "Incorrect calculation of the half-life"}, {"option_key": "D", "hint": "45 minutes would require λ = 0.693/45 = 0.0154 per min. The given λ = 0.0231 corresponds to T₁/₂ = 30 min.", "misconception": "Using an incorrect formula or arithmetic error"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In a nuclear reactor, the function of the moderator is to:", "explanation": "In a nuclear reactor, the moderator (commonly heavy water D₂O, graphite, or ordinary water) slows down fast neutrons produced during fission to thermal energies (~0.025 eV). Slow (thermal) neutrons have a much higher probability of causing fission in ²³⁵U compared to fast neutrons. The moderator achieves this through elastic collisions with neutrons.", "correct_answer": "B", "concept_tags": ["nuclear-reactor", "moderator", "thermal-neutrons", "chain-reaction"], "payload": {"question_id": "cuet-phy-nuclei-decay-10", "subtopic": "Radioactive Decay", "topic_name": "Radioactive Decay", "bloom_level": "understand", "options": [{"key": "A", "text": "Absorb excess neutrons to control the chain reaction", "is_correct": false}, {"key": "B", "text": "Slow down fast neutrons to thermal energies", "is_correct": true}, {"key": "C", "text": "Shield the reactor from radiation leakage", "is_correct": false}, {"key": "D", "text": "Increase the speed of neutrons for efficient fission", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Absorbing excess neutrons is the function of control rods (typically cadmium or boron), not the moderator.", "misconception": "Confusing the role of moderator with control rods"}, {"option_key": "C", "hint": "Radiation shielding is provided by the thick concrete and lead walls around the reactor, not by the moderator.", "misconception": "Confusing the role of moderator with radiation shielding"}, {"option_key": "D", "hint": "The moderator slows down neutrons, not speeds them up. Fast neutrons are less efficient at causing ²³⁵U fission.", "misconception": "Reversing the function of the moderator"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A radioactive nucleus ²³⁶X undergoes a series of alpha and beta-minus decays to finally become ²⁰⁸Y. The number of alpha and beta-minus particles emitted are, respectively:", "explanation": "Let the number of alpha decays = a and beta-minus decays = b. Each alpha decay reduces A by 4 and Z by 2. Each β⁻ decay increases Z by 1 with no change in A. Change in mass number: 236 − 208 = 28 = 4a, so a = 7. For atomic number: if Z_X is the initial atomic number and Z_Y is the final, then Z_X − 2a + b = Z_Y. However, since only A values are given, we use the mass number relation: a = 28/4 = 7. For β⁻ decays, we need Z values. Since this follows the thorium decay series (²³⁶₉₀Th → ²⁰⁸₈₂Pb pattern): Z change = 90 − 82 = 8 = 2a − b = 14 − b, so b = 6. The answer is 7 alpha and 6 beta-minus particles. (Note: In standard decay chains like ²³²Th series, the pattern of 7α and 4β⁻ is typical when Z_X − Z_Y = 2a − b = 10. Here with the given numbers, 7α and 4β⁻ gives Z change = 14 − 4 = 10.)", "correct_answer": "D", "concept_tags": ["alpha-decay", "beta-decay", "decay-series", "mass-number", "atomic-number"], "payload": {"question_id": "cuet-phy-nuclei-decay-11", "subtopic": "Radioactive Decay", "topic_name": "Radioactive Decay", "bloom_level": "analyze", "options": [{"key": "A", "text": "7 alpha and 6 beta-minus", "is_correct": false}, {"key": "B", "text": "6 alpha and 4 beta-minus", "is_correct": false}, {"key": "C", "text": "5 alpha and 8 beta-minus", "is_correct": false}, {"key": "D", "text": "7 alpha and 4 beta-minus", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "While 7 alpha decays is correct (28/4 = 7), the number of β⁻ decays depends on the Z values. In the standard thorium series, 4 β⁻ decays are emitted, not 6.", "misconception": "Incorrect calculation of the number of beta decays"}, {"option_key": "B", "hint": "6 alpha decays would reduce A by only 24 (to 212), not to 208. The mass number change requires exactly 7 alpha decays.", "misconception": "Incorrect calculation of the number of alpha decays"}, {"option_key": "C", "hint": "5 alpha decays would reduce A by only 20 (to 216), which does not match the final mass number of 208.", "misconception": "Incorrect calculation of mass number change in alpha decay"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The activity of a radioactive sample decreases from 6400 disintegrations per second to 100 disintegrations per second in 30 minutes. The half-life of the sample is:", "explanation": "Using A = A₀(1/2)ⁿ, where n is the number of half-lives: 100 = 6400 × (1/2)ⁿ, so (1/2)ⁿ = 100/6400 = 1/64 = (1/2)⁶. Therefore n = 6 half-lives in 30 minutes. Half-life T₁/₂ = 30/6 = 5 minutes.", "correct_answer": "A", "concept_tags": ["activity", "half-life", "exponential-decay", "numerical"], "payload": {"question_id": "cuet-phy-nuclei-decay-12", "subtopic": "Radioactive Decay", "topic_name": "Radioactive Decay", "bloom_level": "apply", "options": [{"key": "A", "text": "5 minutes", "is_correct": true}, {"key": "B", "text": "6 minutes", "is_correct": false}, {"key": "C", "text": "10 minutes", "is_correct": false}, {"key": "D", "text": "15 minutes", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "6 minutes would give n = 30/6 = 5 half-lives, reducing activity by a factor of 2⁵ = 32. But 6400/32 = 200, not 100.", "misconception": "Confusing the number of half-lives with the half-life value"}, {"option_key": "C", "hint": "10 minutes would give n = 30/10 = 3 half-lives, reducing activity by 2³ = 8. But 6400/8 = 800, not 100.", "misconception": "Incorrect division to find number of half-lives"}, {"option_key": "D", "hint": "15 minutes gives n = 2, so activity = 6400/4 = 1600, far from 100. The ratio 6400/100 = 64 = 2⁶ requires 6 half-lives.", "misconception": "Grossly underestimating the number of half-lives required"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): In nuclear fusion, two light nuclei combine to form a heavier nucleus with release of energy.\nReason (R): The binding energy per nucleon of the product nucleus is greater than that of the reacting light nuclei.", "explanation": "Both the assertion and reason are correct, and the reason correctly explains the assertion. In nuclear fusion, light nuclei (like hydrogen isotopes) combine to form a heavier nucleus (like helium). Energy is released because the binding energy per nucleon increases when moving from very light nuclei toward the iron region of the binding energy curve. The mass defect of the product is greater, meaning the product is more tightly bound, and the difference in binding energy is released as kinetic energy and radiation.", "correct_answer": "A", "concept_tags": ["nuclear-fusion", "binding-energy-per-nucleon", "energy-release", "light-nuclei"], "payload": {"question_id": "cuet-phy-nuclei-decay-13", "subtopic": "Radioactive Decay", "topic_name": "Radioactive Decay", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The higher binding energy per nucleon of the product is precisely the reason energy is released. The excess binding energy converts to kinetic energy, so R directly explains A.", "misconception": "Failing to see the direct causal link between binding energy increase and energy release"}, {"option_key": "C", "hint": "The reason is factually correct: on the binding energy curve, fusion products of light nuclei have higher BE/A than the reactants.", "misconception": "Incorrectly thinking binding energy per nucleon decreases in fusion"}, {"option_key": "D", "hint": "The assertion is correct: fusion of light nuclei (e.g., ²H + ³H → ⁴He + n) does release energy. This is the energy source of stars.", "misconception": "Thinking fusion absorbs energy rather than releases it"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): The energy spectrum of electrons emitted in beta-minus decay is continuous, ranging from zero to a maximum value.\nReason (R): In beta-minus decay, the energy is shared between the electron and the antineutrino in varying proportions.", "explanation": "Both A and R are correct, and R is the correct explanation of A. In β⁻ decay, the available energy (Q-value minus the recoil energy of the daughter nucleus) is shared between the emitted electron and the antineutrino. Since this is a three-body decay (daughter nucleus, electron, antineutrino), the electron can carry any fraction of the available energy from nearly zero to the maximum (when the antineutrino gets negligible energy). This variable sharing produces the continuous energy spectrum. Pauli originally postulated the neutrino specifically to explain this continuous spectrum.", "correct_answer": "A", "concept_tags": ["beta-decay", "energy-spectrum", "antineutrino", "continuous-spectrum", "Pauli"], "payload": {"question_id": "cuet-phy-nuclei-decay-14", "subtopic": "Radioactive Decay", "topic_name": "Radioactive Decay", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The energy sharing between the electron and antineutrino is precisely the cause of the continuous spectrum. If only the electron were emitted, the spectrum would be discrete.", "misconception": "Not recognizing that variable energy sharing directly causes the continuous spectrum"}, {"option_key": "C", "hint": "The reason is correct. The three-body nature of β⁻ decay allows the electron-antineutrino energy partition to vary continuously.", "misconception": "Incorrectly thinking beta decay is a two-body process"}, {"option_key": "D", "hint": "The assertion is experimentally verified: beta particles have a continuous energy spectrum from 0 to E_max.", "misconception": "Thinking beta particles have a discrete energy spectrum like alpha particles"}]}}]'::jsonb, 'deploy-2026-03-05-b10');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match the following types of radiation (Column-I) with their properties (Column-II):\n\nColumn-I:\nA. Alpha rays\nB. Beta-minus rays\nC. Gamma rays\nD. Neutrino\n\nColumn-II:\n1. Uncharged, massless (or nearly massless), weakly interacting\n2. Helium nuclei with high ionizing power and low penetration\n3. Electromagnetic radiation with highest penetrating power\n4. Electrons with continuous energy spectrum", "explanation": "Alpha rays are helium nuclei (₂He⁴) with high ionizing power but low penetrating ability (A→2). Beta-minus rays are electrons emitted from the nucleus with a continuous energy spectrum due to energy sharing with the antineutrino (B→4). Gamma rays are electromagnetic radiation with the highest penetrating power among the three types of nuclear radiation (C→3). Neutrinos are uncharged, nearly massless particles that interact very weakly with matter (D→1).", "correct_answer": "B", "concept_tags": ["alpha-rays", "beta-rays", "gamma-rays", "neutrino", "properties"], "payload": {"question_id": "cuet-phy-nuclei-decay-15", "subtopic": "Radioactive Decay", "topic_name": "Radioactive Decay", "bloom_level": "understand", "options": [{"key": "A", "text": "A-2, B-3, C-4, D-1", "is_correct": false}, {"key": "B", "text": "A-2, B-4, C-3, D-1", "is_correct": true}, {"key": "C", "text": "A-4, B-2, C-1, D-3", "is_correct": false}, {"key": "D", "text": "A-1, B-2, C-4, D-3", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This swaps beta rays and gamma rays. Beta rays are electrons (B→4), while gamma rays are electromagnetic radiation (C→3).", "misconception": "Confusing the nature of beta and gamma radiation"}, {"option_key": "C", "hint": "Alpha rays are helium nuclei (A→2), not electrons. This option incorrectly assigns electron properties to alpha particles.", "misconception": "Confusing alpha particles with electrons"}, {"option_key": "D", "hint": "Alpha rays are charged helium nuclei, not uncharged weakly interacting particles. The neutrino has property 1.", "misconception": "Confusing alpha particles with neutrinos"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match the following nuclear reactor components (Column-I) with their materials and functions (Column-II):\n\nColumn-I:\nA. Fuel\nB. Moderator\nC. Control rods\nD. Coolant\n\nColumn-II:\n1. Cadmium or boron rods — absorb excess neutrons\n2. Heavy water or liquid sodium — transfers heat to generate steam\n3. Enriched uranium (²³⁵U) or plutonium (²³⁹Pu) — undergoes fission\n4. Heavy water or graphite — slows down neutrons", "explanation": "The fuel in a nuclear reactor is enriched uranium or plutonium which undergoes fission (A→3). The moderator is heavy water or graphite which slows down fast neutrons to thermal energies (B→4). Control rods are made of cadmium or boron which have high neutron absorption cross-sections to regulate the chain reaction (C→1). The coolant is heavy water or liquid sodium which transfers the heat generated in the reactor core to produce steam for electricity generation (D→2).", "correct_answer": "C", "concept_tags": ["nuclear-reactor", "fuel", "moderator", "control-rods", "coolant"], "payload": {"question_id": "cuet-phy-nuclei-decay-16", "subtopic": "Radioactive Decay", "topic_name": "Radioactive Decay", "bloom_level": "analyze", "options": [{"key": "A", "text": "A-3, B-1, C-4, D-2", "is_correct": false}, {"key": "B", "text": "A-4, B-3, C-2, D-1", "is_correct": false}, {"key": "C", "text": "A-3, B-4, C-1, D-2", "is_correct": true}, {"key": "D", "text": "A-3, B-2, C-1, D-4", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This swaps the moderator and control rods. The moderator slows neutrons (B→4), while control rods absorb neutrons (C→1).", "misconception": "Confusing the functions of moderator and control rods"}, {"option_key": "B", "hint": "This assigns fission to the moderator and neutron slowing to the fuel, which is completely reversed.", "misconception": "Confusing the roles of fuel and moderator in a reactor"}, {"option_key": "D", "hint": "This swaps the coolant and moderator. The coolant transfers heat (D→2), while the moderator slows neutrons (B→4). Both may use heavy water, but their functions differ.", "misconception": "Confusing coolant and moderator because both can use heavy water"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "In gamma decay, the mass number (A) and atomic number (Z) of the nucleus remain unchanged.", "explanation": "This statement is TRUE. Gamma decay involves the emission of a high-energy photon from an excited nuclear state. Since a photon has zero mass number and zero charge, neither the mass number A nor the atomic number Z of the nucleus changes during gamma emission. The nucleus simply transitions from an excited state to a lower energy state (isomeric transition).", "correct_answer": "A", "concept_tags": ["gamma-decay", "mass-number", "atomic-number", "isomeric-transition"], "payload": {"question_id": "cuet-phy-nuclei-decay-17", "subtopic": "Radioactive Decay", "topic_name": "Radioactive Decay", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Gamma photons carry zero mass number and zero charge. Unlike alpha or beta decay, gamma emission does not change A or Z.", "misconception": "Confusing gamma decay with alpha or beta decay where A and/or Z change"}, {"option_key": "C", "hint": "This option is not applicable for this question type.", "misconception": null}, {"option_key": "D", "hint": "This option is not applicable for this question type.", "misconception": null}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "Nuclear fission can be achieved easily by bombarding any heavy nucleus with slow neutrons.", "explanation": "This statement is FALSE. Not all heavy nuclei undergo fission with slow (thermal) neutrons. Only specific fissile nuclei such as ²³⁵U, ²³³U, and ²³⁹Pu can be fissioned by slow neutrons. Other heavy nuclei like ²³⁸U require fast neutrons (energy > 1 MeV) to undergo fission and are called fissionable (not fissile). The distinction between fissile and fissionable materials is crucial in nuclear reactor physics.", "correct_answer": "B", "concept_tags": ["nuclear-fission", "fissile-material", "slow-neutrons", "uranium-235"], "payload": {"question_id": "cuet-phy-nuclei-decay-18", "subtopic": "Radioactive Decay", "topic_name": "Radioactive Decay", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Only specific fissile nuclei (²³⁵U, ²³³U, ²³⁹Pu) undergo fission with slow neutrons. Many heavy nuclei like ²³⁸U do not fission with thermal neutrons.", "misconception": "Assuming all heavy nuclei are equally fissile with slow neutrons"}, {"option_key": "C", "hint": "This option is not applicable for this question type.", "misconception": null}, {"option_key": "D", "hint": "This option is not applicable for this question type.", "misconception": null}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "A radioactive sample has a decay constant λ = 0.1 per second. If the sample initially contains 10⁶ atoms, its initial activity (rate of disintegration) is _____ disintegrations per second.", "explanation": "Activity is defined as A = λN, where λ is the decay constant and N is the number of radioactive atoms. Initial activity A₀ = λN₀ = 0.1 × 10⁶ = 10⁵ = 1,00,000 disintegrations per second (or 10⁵ Bq). Activity represents the number of nuclear disintegrations occurring per unit time.", "correct_answer": "D", "concept_tags": ["activity", "decay-constant", "number-of-atoms", "disintegration-rate"], "payload": {"question_id": "cuet-phy-nuclei-decay-19", "subtopic": "Radioactive Decay", "topic_name": "Radioactive Decay", "bloom_level": "apply", "options": [{"key": "A", "text": "10⁷", "is_correct": false}, {"key": "B", "text": "10⁶", "is_correct": false}, {"key": "C", "text": "10⁴", "is_correct": false}, {"key": "D", "text": "10⁵", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "10⁷ would mean A = 10 × N₀, but the decay constant is 0.1 (less than 1), so A must be less than N₀.", "misconception": "Multiplying instead of correctly applying A = λN"}, {"option_key": "B", "hint": "10⁶ equals N₀ itself. Activity A = λN₀ = 0.1 × 10⁶ = 10⁵, not 10⁶.", "misconception": "Confusing the number of atoms with the activity"}, {"option_key": "C", "hint": "10⁴ would require λ = 10⁴/10⁶ = 0.01, but the given λ is 0.1. Check: 0.1 × 10⁶ = 10⁵.", "misconception": "Arithmetic error in computing λN"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "medium", "question_text": "A hospital uses a radioactive isotope ¹³¹I (iodine-131) with a half-life of 8 days for thyroid diagnosis. A fresh sample has an activity of 4.8 × 10⁸ Bq on the day it is delivered. The hospital plans to use it when the activity drops to 6 × 10⁷ Bq.\n\nAfter how many days from delivery can the hospital use the sample?", "explanation": "Using A = A₀(1/2)ⁿ, where n = t/T₁/₂. We need: 6 × 10⁷ = 4.8 × 10⁸ × (1/2)ⁿ. So (1/2)ⁿ = 6 × 10⁷ / 4.8 × 10⁸ = 1/8 = (1/2)³. Therefore n = 3 half-lives. Time t = 3 × 8 = 24 days. The hospital can use the sample 24 days after delivery when its activity has decreased to the required level.", "correct_answer": "C", "concept_tags": ["half-life", "activity", "iodine-131", "medical-application", "exponential-decay"], "payload": {"question_id": "cuet-phy-nuclei-decay-20", "subtopic": "Radioactive Decay", "topic_name": "Radioactive Decay", "bloom_level": "apply", "options": [{"key": "A", "text": "8 days", "is_correct": false}, {"key": "B", "text": "16 days", "is_correct": false}, {"key": "C", "text": "24 days", "is_correct": true}, {"key": "D", "text": "32 days", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "After 8 days (1 half-life), activity = 4.8 × 10⁸ / 2 = 2.4 × 10⁸ Bq, which is still much higher than the required 6 × 10⁷ Bq.", "misconception": "Assuming only one half-life is needed without checking the activity ratio"}, {"option_key": "B", "hint": "After 16 days (2 half-lives), activity = 4.8 × 10⁸ / 4 = 1.2 × 10⁸ Bq, still above the target of 6 × 10⁷ Bq.", "misconception": "Insufficient number of half-lives calculated"}, {"option_key": "D", "hint": "After 32 days (4 half-lives), activity = 4.8 × 10⁸ / 16 = 3 × 10⁷ Bq, which overshoots below the target. The ratio 4.8 × 10⁸ / 6 × 10⁷ = 8 = 2³ requires exactly 3 half-lives = 24 days.", "misconception": "Overcounting the number of half-lives required"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The value of 1 atomic mass unit (1 u) in terms of energy is approximately:", "explanation": "By Einstein''s mass-energy equivalence E = mc², 1 atomic mass unit (1 u = 1.66054 × 10⁻²⁷ kg) corresponds to an energy of 931.5 MeV. This conversion factor is fundamental in nuclear physics for calculating binding energies and mass defects.", "correct_answer": "C", "concept_tags": ["atomic-mass-unit", "mass-energy-equivalence", "MeV"], "payload": {"question_id": "cuet-phy-nuclei-properties-01", "subtopic": "Nuclear Properties and Binding Energy", "topic_name": "Nuclear Properties and Binding Energy", "bloom_level": "remember", "options": [{"key": "A", "text": "931.5 keV", "is_correct": false}, {"key": "B", "text": "931.5 GeV", "is_correct": false}, {"key": "C", "text": "931.5 MeV", "is_correct": true}, {"key": "D", "text": "9.315 MeV", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "931.5 keV is a thousand times smaller than the correct value. The correct unit is MeV (mega electron volt), not keV (kilo electron volt).", "misconception": "Confusing keV with MeV; 1 MeV = 1000 keV"}, {"option_key": "B", "hint": "931.5 GeV is a thousand times larger than the correct value. 1 GeV = 1000 MeV, so this would be 931,500 MeV.", "misconception": "Confusing GeV with MeV"}, {"option_key": "D", "hint": "9.315 MeV is off by a factor of 100. The standard value is 931.5 MeV per atomic mass unit.", "misconception": "Misplacing the decimal point in the conversion factor"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The nuclear radius R is related to the mass number A by the relation R = R₀A^(1/3). The value of R₀ is approximately:", "explanation": "Experimentally, the nuclear radius follows the empirical formula R = R₀A^(1/3), where R₀ ≈ 1.2 fm (1.2 × 10⁻¹⁵ m). This relation shows that nuclear volume is directly proportional to the mass number A, implying constant nuclear density.", "correct_answer": "B", "concept_tags": ["nuclear-radius", "mass-number", "fermi"], "payload": {"question_id": "cuet-phy-nuclei-properties-02", "subtopic": "Nuclear Properties and Binding Energy", "topic_name": "Nuclear Properties and Binding Energy", "bloom_level": "remember", "options": [{"key": "A", "text": "1.2 × 10⁻¹⁰ m", "is_correct": false}, {"key": "B", "text": "1.2 × 10⁻¹⁵ m", "is_correct": true}, {"key": "C", "text": "1.2 × 10⁻²⁰ m", "is_correct": false}, {"key": "D", "text": "1.2 × 10⁻⁸ m", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "10⁻¹⁰ m (1 Å) is the order of atomic size, not nuclear size. Nuclei are about 100,000 times smaller than atoms.", "misconception": "Confusing atomic radius with nuclear radius"}, {"option_key": "C", "hint": "10⁻²⁰ m is far too small even for a nucleus. Nuclear sizes are of the order of femtometres (10⁻¹⁵ m).", "misconception": "Using an incorrect order of magnitude for nuclear dimensions"}, {"option_key": "D", "hint": "10⁻⁸ m is the order of atomic diameter, not nuclear radius. The nucleus is roughly 10⁵ times smaller than the atom.", "misconception": "Confusing atomic dimensions with nuclear dimensions"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Nuclei having the same mass number but different atomic numbers are called:", "explanation": "Isobars are nuclei that share the same mass number (A) but have different atomic numbers (Z). For example, ¹⁴C (Z = 6) and ¹⁴N (Z = 7) are isobars. Isotopes have the same Z but different A; isotones have the same neutron number (A − Z).", "correct_answer": "A", "concept_tags": ["isobars", "mass-number", "atomic-number", "nuclear-terminology"], "payload": {"question_id": "cuet-phy-nuclei-properties-03", "subtopic": "Nuclear Properties and Binding Energy", "topic_name": "Nuclear Properties and Binding Energy", "bloom_level": "remember", "options": [{"key": "A", "text": "Isobars", "is_correct": true}, {"key": "B", "text": "Isotopes", "is_correct": false}, {"key": "C", "text": "Isotones", "is_correct": false}, {"key": "D", "text": "Isomers", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Isotopes have the same atomic number (Z) but different mass numbers (A). The question states different atomic numbers, so these cannot be isotopes.", "misconception": "Confusing isotopes (same Z, different A) with isobars (same A, different Z)"}, {"option_key": "C", "hint": "Isotones have the same number of neutrons (N = A − Z) but different atomic numbers and mass numbers.", "misconception": "Confusing isotones (same N) with isobars (same A)"}, {"option_key": "D", "hint": "Isomers are nuclei with the same Z and A but in different energy states. They are not defined by having different atomic numbers.", "misconception": "Confusing nuclear isomers with isobars"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The density of nuclear matter is approximately:", "explanation": "Nuclear density is nearly constant for all nuclei and is approximately 2.3 × 10¹⁷ kg/m³. This follows from the relation R = R₀A^(1/3), which means volume V ∝ A. Since mass is also proportional to A (mass ≈ A × u), the density ρ = mass/volume is independent of A.", "correct_answer": "D", "concept_tags": ["nuclear-density", "nuclear-volume", "mass-number"], "payload": {"question_id": "cuet-phy-nuclei-properties-04", "subtopic": "Nuclear Properties and Binding Energy", "topic_name": "Nuclear Properties and Binding Energy", "bloom_level": "remember", "options": [{"key": "A", "text": "2.3 × 10³ kg/m³", "is_correct": false}, {"key": "B", "text": "2.3 × 10¹⁰ kg/m³", "is_correct": false}, {"key": "C", "text": "2.3 × 10²⁷ kg/m³", "is_correct": false}, {"key": "D", "text": "2.3 × 10¹⁷ kg/m³", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "10³ kg/m³ is the density of water. Nuclear matter is about 10¹⁴ times denser than water.", "misconception": "Confusing ordinary matter density with nuclear density"}, {"option_key": "B", "hint": "10¹⁰ kg/m³ is too low for nuclear matter. The incredibly small nuclear volume leads to a much higher density (~10¹⁷ kg/m³).", "misconception": "Underestimating nuclear density by several orders of magnitude"}, {"option_key": "C", "hint": "10²⁷ kg/m³ is ten orders of magnitude too high. The correct nuclear density is about 2.3 × 10¹⁷ kg/m³.", "misconception": "Overestimating nuclear density"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The ratio of the nuclear radii of two nuclei with mass numbers 27 and 125 is:", "explanation": "Using R = R₀A^(1/3), the ratio R₁/R₂ = (A₁/A₂)^(1/3) = (27/125)^(1/3) = 3/5. Here, 27^(1/3) = 3 and 125^(1/3) = 5.", "correct_answer": "B", "concept_tags": ["nuclear-radius", "mass-number", "ratio-calculation"], "payload": {"question_id": "cuet-phy-nuclei-properties-05", "subtopic": "Nuclear Properties and Binding Energy", "topic_name": "Nuclear Properties and Binding Energy", "bloom_level": "apply", "options": [{"key": "A", "text": "27 : 125", "is_correct": false}, {"key": "B", "text": "3 : 5", "is_correct": true}, {"key": "C", "text": "5 : 3", "is_correct": false}, {"key": "D", "text": "9 : 25", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The ratio of radii is not the same as the ratio of mass numbers. R ∝ A^(1/3), so the cube root must be taken.", "misconception": "Assuming nuclear radius is directly proportional to A instead of A^(1/3)"}, {"option_key": "C", "hint": "The ratio 5:3 is inverted. Since the first nucleus has the smaller mass number (27), it has the smaller radius, so the ratio is 3:5.", "misconception": "Reversing the order of the ratio"}, {"option_key": "D", "hint": "9:25 = (3:5)² corresponds to the ratio of surface areas, not radii. The radius ratio uses the cube root of A.", "misconception": "Using A^(2/3) instead of A^(1/3) for the radius relation"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The mass defect of a helium nucleus ⁴He is 0.0304 u. The binding energy of the helium nucleus is approximately:", "explanation": "Binding energy = mass defect × 931.5 MeV/u = 0.0304 × 931.5 = 28.3 MeV. This is the energy required to completely separate all nucleons (2 protons and 2 neutrons) in the ⁴He nucleus.", "correct_answer": "C", "concept_tags": ["binding-energy", "mass-defect", "helium-nucleus", "numerical"], "payload": {"question_id": "cuet-phy-nuclei-properties-06", "subtopic": "Nuclear Properties and Binding Energy", "topic_name": "Nuclear Properties and Binding Energy", "bloom_level": "apply", "options": [{"key": "A", "text": "28.3 keV", "is_correct": false}, {"key": "B", "text": "7.07 MeV", "is_correct": false}, {"key": "C", "text": "28.3 MeV", "is_correct": true}, {"key": "D", "text": "283 MeV", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "28.3 keV uses the wrong unit. The conversion factor 931.5 already gives MeV, not keV. The correct answer is 28.3 MeV.", "misconception": "Confusing MeV with keV in the mass-energy conversion"}, {"option_key": "B", "hint": "7.07 MeV is the binding energy per nucleon (28.3/4), not the total binding energy of the nucleus.", "misconception": "Confusing total binding energy with binding energy per nucleon"}, {"option_key": "D", "hint": "283 MeV is ten times too large. Check: 0.0304 × 931.5 ≈ 28.3 MeV, not 283 MeV.", "misconception": "Arithmetic error — misplacing the decimal point"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The binding energy per nucleon is maximum for nuclei in the vicinity of:", "explanation": "The binding energy per nucleon (BE/A) curve shows a maximum of about 8.75 MeV/nucleon near iron (A ≈ 56). This makes iron-56 one of the most stable nuclei. Lighter nuclei gain stability through fusion, while heavier nuclei gain stability through fission, both moving toward this peak.", "correct_answer": "A", "concept_tags": ["binding-energy-per-nucleon", "nuclear-stability", "iron-56", "BE-curve"], "payload": {"question_id": "cuet-phy-nuclei-properties-07", "subtopic": "Nuclear Properties and Binding Energy", "topic_name": "Nuclear Properties and Binding Energy", "bloom_level": "understand", "options": [{"key": "A", "text": "Iron (A ≈ 56)", "is_correct": true}, {"key": "B", "text": "Uranium (A ≈ 238)", "is_correct": false}, {"key": "C", "text": "Helium (A = 4)", "is_correct": false}, {"key": "D", "text": "Hydrogen (A = 1)", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Uranium has a lower BE/A (~7.6 MeV) than iron. Heavy nuclei beyond iron have decreasing BE/A, which is why fission of heavy nuclei releases energy.", "misconception": "Assuming the heaviest nuclei are the most stable"}, {"option_key": "C", "hint": "⁴He has an unusually high BE/A (~7.07 MeV) for its mass number but it is still less than that of iron (~8.75 MeV). ⁴He is a local peak, not the global maximum.", "misconception": "Confusing the local stability peak of He-4 with the overall maximum"}, {"option_key": "D", "hint": "Hydrogen (¹H) has no binding energy at all since it consists of only one proton — there is nothing to bind.", "misconception": "Not understanding that a single nucleon has zero binding energy"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "If the nucleus of ²⁷Al has a nuclear radius of approximately 3.6 fm, the nuclear radius of ¹²⁵Te is approximately:", "explanation": "Using R = R₀A^(1/3), R(Te)/R(Al) = (125/27)^(1/3) = 5/3. Therefore, R(Te) = (5/3) × 3.6 = 6.0 fm. We use the fact that 125^(1/3) = 5 and 27^(1/3) = 3.", "correct_answer": "D", "concept_tags": ["nuclear-radius", "mass-number", "cube-root", "numerical"], "payload": {"question_id": "cuet-phy-nuclei-properties-08", "subtopic": "Nuclear Properties and Binding Energy", "topic_name": "Nuclear Properties and Binding Energy", "bloom_level": "apply", "options": [{"key": "A", "text": "16.7 fm", "is_correct": false}, {"key": "B", "text": "2.16 fm", "is_correct": false}, {"key": "C", "text": "10.0 fm", "is_correct": false}, {"key": "D", "text": "6.0 fm", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "16.7 fm results from using the ratio of mass numbers directly (3.6 × 125/27) instead of using the cube root relation R ∝ A^(1/3).", "misconception": "Assuming radius is directly proportional to mass number instead of A^(1/3)"}, {"option_key": "B", "hint": "2.16 fm is obtained by dividing instead of multiplying. Since Te has a larger A, its radius must be larger than Al''s radius of 3.6 fm.", "misconception": "Inverting the ratio — dividing by (5/3) instead of multiplying"}, {"option_key": "C", "hint": "10.0 fm is too large. The correct ratio is (125/27)^(1/3) = 5/3, giving 3.6 × 5/3 = 6.0 fm.", "misconception": "Using an incorrect cube root value"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Which of the following is NOT a property of nuclear forces?", "explanation": "Nuclear forces are charge-independent — they act equally between p-p, n-n, and p-n pairs. They are short-range (effective only up to ~few femtometres), strongly attractive, and saturated (each nucleon interacts only with its nearest neighbours). They are NOT long-range forces like gravity or electrostatic forces.", "correct_answer": "B", "concept_tags": ["nuclear-forces", "short-range", "charge-independent", "saturation"], "payload": {"question_id": "cuet-phy-nuclei-properties-09", "subtopic": "Nuclear Properties and Binding Energy", "topic_name": "Nuclear Properties and Binding Energy", "bloom_level": "understand", "options": [{"key": "A", "text": "They are short-range forces", "is_correct": false}, {"key": "B", "text": "They obey the inverse square law", "is_correct": true}, {"key": "C", "text": "They are charge-independent", "is_correct": false}, {"key": "D", "text": "They show the property of saturation", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Nuclear forces are indeed short-range, operating effectively within ~2–3 fm. This is a true property, so it cannot be the answer.", "misconception": null}, {"option_key": "C", "hint": "Nuclear forces are indeed charge-independent — the strong force between two protons equals that between two neutrons or a proton-neutron pair. This is a true property.", "misconception": null}, {"option_key": "D", "hint": "Saturation is a genuine property of nuclear forces meaning each nucleon interacts only with a limited number of neighbours. This explains why BE/A remains roughly constant.", "misconception": null}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The mass of a nucleus is always less than the sum of the masses of its constituent protons and neutrons. This difference in mass is called:", "explanation": "The mass defect (Δm) is the difference between the sum of masses of individual nucleons and the actual nuclear mass: Δm = [Zmₚ + (A − Z)mₙ] − M. This ''missing'' mass has been converted into binding energy (BE = Δm × c²) that holds the nucleus together.", "correct_answer": "C", "concept_tags": ["mass-defect", "binding-energy", "nucleons", "mass-energy-equivalence"], "payload": {"question_id": "cuet-phy-nuclei-properties-10", "subtopic": "Nuclear Properties and Binding Energy", "topic_name": "Nuclear Properties and Binding Energy", "bloom_level": "understand", "options": [{"key": "A", "text": "Packing fraction", "is_correct": false}, {"key": "B", "text": "Binding energy", "is_correct": false}, {"key": "C", "text": "Mass defect", "is_correct": true}, {"key": "D", "text": "Mass excess", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Packing fraction is defined as (exact atomic mass − mass number)/mass number. It is related to but not the same as mass defect.", "misconception": "Confusing packing fraction with mass defect"}, {"option_key": "B", "hint": "Binding energy is the energy equivalent of the mass defect (BE = Δm × 931.5 MeV), not the mass difference itself.", "misconception": "Confusing the mass difference with its energy equivalent"}, {"option_key": "D", "hint": "Mass excess is defined as (atomic mass − A) in atomic mass units. It is a different quantity from mass defect.", "misconception": "Confusing mass excess with mass defect"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The masses of a proton, neutron, and the ¹⁶O nucleus are 1.00728 u, 1.00866 u, and 15.99053 u respectively. The binding energy per nucleon of ¹⁶O is approximately:", "explanation": "For ¹⁶O: Z = 8, A = 16, N = 8. Sum of masses = 8(1.00728) + 8(1.00866) = 8.05824 + 8.06928 = 16.12752 u. Mass defect Δm = 16.12752 − 15.99053 = 0.13699 u. Binding energy = 0.13699 × 931.5 = 127.6 MeV. BE per nucleon = 127.6/16 ≈ 7.97 MeV/nucleon.", "correct_answer": "A", "concept_tags": ["binding-energy-per-nucleon", "mass-defect", "oxygen-16", "numerical-problem"], "payload": {"question_id": "cuet-phy-nuclei-properties-11", "subtopic": "Nuclear Properties and Binding Energy", "topic_name": "Nuclear Properties and Binding Energy", "bloom_level": "analyze", "options": [{"key": "A", "text": "7.97 MeV/nucleon", "is_correct": true}, {"key": "B", "text": "127.6 MeV/nucleon", "is_correct": false}, {"key": "C", "text": "0.137 MeV/nucleon", "is_correct": false}, {"key": "D", "text": "5.24 MeV/nucleon", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "127.6 MeV is the total binding energy of ¹⁶O, not the binding energy per nucleon. You must divide by A = 16 to get BE per nucleon.", "misconception": "Forgetting to divide total binding energy by the mass number"}, {"option_key": "C", "hint": "0.137 MeV/nucleon comes from dividing the mass defect in u by A without converting to MeV. You must multiply Δm by 931.5 MeV/u first.", "misconception": "Forgetting to convert mass defect from atomic mass units to MeV"}, {"option_key": "D", "hint": "5.24 MeV/nucleon does not match any correct calculation path. Recheck: Δm = 0.137 u → BE = 127.6 MeV → BE/A = 7.97 MeV.", "misconception": "Arithmetic error in computing sum of nucleon masses or mass defect"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A nucleus has a radius of 3.6 fm. If the nuclear density is approximately 2.3 × 10¹⁷ kg/m³, the approximate mass number of this nucleus is:", "explanation": "Using R = R₀A^(1/3), A = (R/R₀)³ = (3.6/1.2)³ = (3)³ = 27. Alternatively, from density: mass = ρ × (4/3)πR³ and mass ≈ A × 1.66 × 10⁻²⁷ kg. Either way, A = 27, which corresponds to aluminium (²⁷Al).", "correct_answer": "B", "concept_tags": ["nuclear-radius", "mass-number", "nuclear-density", "numerical-problem"], "payload": {"question_id": "cuet-phy-nuclei-properties-12", "subtopic": "Nuclear Properties and Binding Energy", "topic_name": "Nuclear Properties and Binding Energy", "bloom_level": "analyze", "options": [{"key": "A", "text": "8", "is_correct": false}, {"key": "B", "text": "27", "is_correct": true}, {"key": "C", "text": "64", "is_correct": false}, {"key": "D", "text": "125", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "A = 8 gives R = 1.2 × 8^(1/3) = 1.2 × 2 = 2.4 fm, not 3.6 fm.", "misconception": "Incorrectly computing (R/R₀)³"}, {"option_key": "C", "hint": "A = 64 gives R = 1.2 × 64^(1/3) = 1.2 × 4 = 4.8 fm, which is larger than 3.6 fm.", "misconception": "Using R/R₀ = 4 instead of the correct value 3"}, {"option_key": "D", "hint": "A = 125 gives R = 1.2 × 125^(1/3) = 1.2 × 5 = 6.0 fm, much larger than 3.6 fm.", "misconception": "Using R/R₀ = 5 instead of the correct value 3"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): The density of nuclear matter is independent of the mass number A.\nReason (R): The nuclear radius is proportional to the cube root of the mass number, i.e., R = R₀A^(1/3).", "explanation": "Both A and R are correct, and R is the correct explanation of A. Since R ∝ A^(1/3), the nuclear volume V = (4/3)πR³ ∝ A. The nuclear mass is also proportional to A (mass ≈ A × u). Therefore, density ρ = mass/volume ∝ A/A = constant, independent of A. The R = R₀A^(1/3) relation directly leads to constant density.", "correct_answer": "A", "concept_tags": ["nuclear-density", "nuclear-radius", "mass-number", "assertion-reasoning"], "payload": {"question_id": "cuet-phy-nuclei-properties-13", "subtopic": "Nuclear Properties and Binding Energy", "topic_name": "Nuclear Properties and Binding Energy", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R directly explains A: the R ∝ A^(1/3) relation makes V ∝ A, and since mass ∝ A, density becomes independent of A. The reason is the correct explanation.", "misconception": "Failing to see the logical connection between R ∝ A^(1/3) and constant nuclear density"}, {"option_key": "C", "hint": "The reason R = R₀A^(1/3) is experimentally verified and is a well-established empirical formula. It is definitely correct.", "misconception": "Doubting the validity of the nuclear radius formula"}, {"option_key": "D", "hint": "The assertion is correct — nuclear density (~2.3 × 10¹⁷ kg/m³) is indeed the same for all nuclei regardless of mass number.", "misconception": "Incorrectly believing nuclear density varies with mass number"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): The binding energy per nucleon for ⁵⁶Fe is higher than that for ²³⁸U.\nReason (R): Nuclear forces obey the inverse square law similar to gravitational and electrostatic forces.", "explanation": "The assertion is correct — ⁵⁶Fe has the highest BE/A (~8.75 MeV) while ²³⁸U has a lower value (~7.6 MeV). However, the reason is incorrect — nuclear forces do NOT obey the inverse square law. Nuclear forces are short-range (effective only within ~2–3 fm) and do not follow any simple power law like 1/r².", "correct_answer": "C", "concept_tags": ["binding-energy-per-nucleon", "nuclear-forces", "iron-56", "uranium-238", "assertion-reasoning"], "payload": {"question_id": "cuet-phy-nuclei-properties-14", "subtopic": "Nuclear Properties and Binding Energy", "topic_name": "Nuclear Properties and Binding Energy", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": true}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Even if both statements were correct, the inverse square law for nuclear forces would not explain why iron has the highest BE/A. But more importantly, the reason itself is factually wrong.", "misconception": "Incorrectly believing nuclear forces follow the inverse square law"}, {"option_key": "B", "hint": "The reason statement is factually incorrect — nuclear forces are short-range and do NOT obey the inverse square law. So option B cannot apply.", "misconception": "Accepting the inverse square law claim for nuclear forces as true"}, {"option_key": "D", "hint": "The assertion is correct — ⁵⁶Fe does have a higher BE/A than ²³⁸U. This is a well-known fact from the BE/A curve.", "misconception": "Not knowing the relative positions of Fe and U on the BE/A curve"}]}}]'::jsonb, 'deploy-2026-03-05-b10');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match Column I with Column II:\n\nColumn I:\n(P) Isotopes\n(Q) Isobars\n(R) Isotones\n(S) Isomers\n\nColumn II:\n(1) Same mass number, different atomic number\n(2) Same atomic number, different mass number\n(3) Same neutron number, different atomic number\n(4) Same Z and A, different nuclear energy states", "explanation": "Isotopes have the same atomic number Z but different mass number A (P→2). Isobars have the same mass number A but different atomic number Z (Q→1). Isotones have the same neutron number N but different Z (R→3). Isomers have the same Z and A but exist in different excited nuclear energy states (S→4).", "correct_answer": "D", "concept_tags": ["isotopes", "isobars", "isotones", "isomers", "nuclear-terminology", "match-the-following"], "payload": {"question_id": "cuet-phy-nuclei-properties-15", "subtopic": "Nuclear Properties and Binding Energy", "topic_name": "Nuclear Properties and Binding Energy", "bloom_level": "understand", "options": [{"key": "A", "text": "P→1, Q→2, R→3, S→4", "is_correct": false}, {"key": "B", "text": "P→2, Q→1, R→4, S→3", "is_correct": false}, {"key": "C", "text": "P→3, Q→1, R→2, S→4", "is_correct": false}, {"key": "D", "text": "P→2, Q→1, R→3, S→4", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "P→1 means isotopes have the same mass number — this is wrong. Isotopes have the same atomic number (Z), not the same mass number. P should match with 2.", "misconception": "Confusing the definition of isotopes with isobars"}, {"option_key": "B", "hint": "R→4 implies isotones have different energy states — this is wrong. Isotones share the same neutron number. R should match with 3.", "misconception": "Confusing isotones with isomers"}, {"option_key": "C", "hint": "P→3 means isotopes have the same neutron number — this is wrong. Isotopes have the same atomic number (Z). P should match with 2.", "misconception": "Confusing isotopes with isotones"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match Column I with Column II:\n\nColumn I:\n(P) Binding energy per nucleon of ²H\n(Q) Binding energy per nucleon of ⁴He\n(R) Binding energy per nucleon of ⁵⁶Fe\n(S) Binding energy per nucleon of ²³⁸U\n\nColumn II:\n(1) ~1.1 MeV\n(2) ~7.6 MeV\n(3) ~8.75 MeV\n(4) ~7.07 MeV", "explanation": "²H (deuteron) has BE/A ≈ 1.1 MeV (P→1), being the simplest bound nucleus. ⁴He has BE/A ≈ 7.07 MeV (Q→4), showing exceptional stability. ⁵⁶Fe has the highest BE/A ≈ 8.75 MeV (R→3), making it the most stable nucleus. ²³⁸U has BE/A ≈ 7.6 MeV (S→2), lower than iron due to greater Coulomb repulsion.", "correct_answer": "B", "concept_tags": ["binding-energy-per-nucleon", "BE-curve", "deuterium", "helium", "iron", "uranium", "match-the-following"], "payload": {"question_id": "cuet-phy-nuclei-properties-16", "subtopic": "Nuclear Properties and Binding Energy", "topic_name": "Nuclear Properties and Binding Energy", "bloom_level": "analyze", "options": [{"key": "A", "text": "P→1, Q→4, R→2, S→3", "is_correct": false}, {"key": "B", "text": "P→1, Q→4, R→3, S→2", "is_correct": true}, {"key": "C", "text": "P→4, Q→1, R→3, S→2", "is_correct": false}, {"key": "D", "text": "P→1, Q→3, R→4, S→2", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "R→2 assigns 7.6 MeV to ⁵⁶Fe, but iron has the maximum BE/A (~8.75 MeV) on the curve. R should match with 3.", "misconception": "Not knowing that iron has the highest binding energy per nucleon"}, {"option_key": "C", "hint": "P→4 assigns ~7.07 MeV to deuterium, but ²H is the weakest bound nucleus with BE/A ≈ 1.1 MeV. P should match with 1.", "misconception": "Confusing deuterium''s BE/A with that of helium-4"}, {"option_key": "D", "hint": "Q→3 assigns ~8.75 MeV to ⁴He, but helium has BE/A ≈ 7.07 MeV. The maximum ~8.75 MeV belongs to ⁵⁶Fe.", "misconception": "Assigning the maximum BE/A to helium instead of iron"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The nuclear force between two nucleons is independent of their electric charge.", "explanation": "This statement is TRUE. Nuclear forces are charge-independent, meaning the strong nuclear force between two protons, two neutrons, or a proton-neutron pair is essentially the same. This is a fundamental property of the strong nuclear interaction, confirmed by scattering experiments.", "correct_answer": "A", "concept_tags": ["nuclear-forces", "charge-independence", "true-false"], "payload": {"question_id": "cuet-phy-nuclei-properties-17", "subtopic": "Nuclear Properties and Binding Energy", "topic_name": "Nuclear Properties and Binding Energy", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Nuclear (strong) forces are indeed charge-independent. The nuclear force between p-p, n-n, and p-n pairs is the same. Do not confuse the nuclear force with the Coulomb force, which is charge-dependent.", "misconception": "Confusing nuclear force with electromagnetic force between protons"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "medium", "question_text": "The nuclear density increases with increasing mass number A.", "explanation": "This statement is FALSE. Nuclear density is approximately constant (~2.3 × 10¹⁷ kg/m³) for all nuclei, regardless of mass number. Since R = R₀A^(1/3), the volume V = (4/3)πR³ ∝ A, and mass ∝ A, so density ρ = mass/volume remains constant and is independent of A.", "correct_answer": "B", "concept_tags": ["nuclear-density", "mass-number", "constant-density", "true-false"], "payload": {"question_id": "cuet-phy-nuclei-properties-18", "subtopic": "Nuclear Properties and Binding Energy", "topic_name": "Nuclear Properties and Binding Energy", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Nuclear density does NOT increase with A. Since volume ∝ A and mass ∝ A, the density remains constant. This is a direct consequence of R ∝ A^(1/3).", "misconception": "Assuming heavier nuclei are denser, similar to how denser elements exist in everyday life"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "The mass defect of a nucleus is defined as Δm = [Zmₚ + (A − Z)mₙ] − M. The binding energy of the nucleus is obtained by multiplying the mass defect by _____ MeV/u.", "explanation": "The binding energy is obtained by converting the mass defect from atomic mass units to energy using Einstein''s relation E = Δmc². The conversion factor is 1 u × c² = 931.5 MeV. Therefore, BE = Δm × 931.5 MeV/u. This factor comes from calculating (1.66054 × 10⁻²⁷ kg)(3 × 10⁸ m/s)² and converting joules to MeV.", "correct_answer": "C", "concept_tags": ["mass-defect", "binding-energy", "mass-energy-equivalence", "conversion-factor", "fill-in-blanks"], "payload": {"question_id": "cuet-phy-nuclei-properties-19", "subtopic": "Nuclear Properties and Binding Energy", "topic_name": "Nuclear Properties and Binding Energy", "bloom_level": "apply", "options": [{"key": "A", "text": "1.5", "is_correct": false}, {"key": "B", "text": "93.15", "is_correct": false}, {"key": "C", "text": "931.5", "is_correct": true}, {"key": "D", "text": "9315", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "1.5 MeV/u is far too small. The correct conversion factor 1 u = 931.5 MeV/c² is a standard value that must be memorised.", "misconception": null}, {"option_key": "B", "hint": "93.15 is off by a factor of 10. The correct value is 931.5 MeV, not 93.15 MeV.", "misconception": "Misplacing the decimal point in the conversion factor"}, {"option_key": "D", "hint": "9315 is ten times too large. The standard conversion factor is 931.5 MeV per atomic mass unit.", "misconception": "Misplacing the decimal point in the conversion factor"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "hard", "question_text": "In a nuclear physics laboratory, a researcher measures the mass of a ⁵⁶Fe nucleus to be 55.9207 u. Given that the mass of a proton is 1.00728 u and the mass of a neutron is 1.00866 u, and ⁵⁶Fe has Z = 26 and A = 56, the researcher wants to determine how tightly bound this nucleus is. What is the binding energy per nucleon of ⁵⁶Fe?", "explanation": "Step 1: Sum of nucleon masses = 26(1.00728) + 30(1.00866) = 26.18928 + 30.25980 = 56.44908 u.\nStep 2: Mass defect Δm = 56.44908 − 55.9207 = 0.52838 u.\nStep 3: Total binding energy = 0.52838 × 931.5 = 492.2 MeV.\nStep 4: BE per nucleon = 492.2/56 ≈ 8.79 MeV/nucleon.\nThis confirms that ⁵⁶Fe has one of the highest BE/A values, making it among the most stable nuclei.", "correct_answer": "D", "concept_tags": ["binding-energy-per-nucleon", "mass-defect", "iron-56", "numerical-problem", "scenario-based"], "payload": {"question_id": "cuet-phy-nuclei-properties-20", "subtopic": "Nuclear Properties and Binding Energy", "topic_name": "Nuclear Properties and Binding Energy", "bloom_level": "evaluate", "options": [{"key": "A", "text": "492.2 MeV/nucleon", "is_correct": false}, {"key": "B", "text": "0.528 MeV/nucleon", "is_correct": false}, {"key": "C", "text": "18.93 MeV/nucleon", "is_correct": false}, {"key": "D", "text": "8.79 MeV/nucleon", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "492.2 MeV is the total binding energy of the ⁵⁶Fe nucleus, not the binding energy per nucleon. Divide by A = 56 to get BE/A.", "misconception": "Forgetting to divide total binding energy by the number of nucleons"}, {"option_key": "B", "hint": "0.528 MeV/nucleon results from dividing the mass defect in atomic mass units by A without converting to MeV. Multiply Δm by 931.5 first.", "misconception": "Forgetting to apply the 931.5 MeV/u conversion factor"}, {"option_key": "C", "hint": "18.93 MeV/nucleon is approximately twice the correct value. Recheck arithmetic: 492.2/56 ≈ 8.79, not 18.93.", "misconception": "Arithmetic error in the division step"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A potentiometer wire of length 100 cm has a potential drop of 1 V across it. The balancing length for a cell of EMF 0.4 V is:", "explanation": "The potential gradient k = V/L = 1/100 = 0.01 V/cm. For balance, E = kl, so l = E/k = 0.4/0.01 = 40 cm. At the balance point, the potential drop across length l equals the EMF of the cell, and no current is drawn from the cell being measured.", "correct_answer": "A", "concept_tags": ["potentiometer", "balancing-length", "potential-gradient", "EMF"], "payload": {"question_id": "cuet-phy-current-instruments-07", "subtopic": "Electrical Instruments", "topic_name": "Electrical Instruments", "bloom_level": "apply", "options": [{"key": "A", "text": "40 cm", "is_correct": true}, {"key": "B", "text": "60 cm", "is_correct": false}, {"key": "C", "text": "25 cm", "is_correct": false}, {"key": "D", "text": "4 cm", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "60 cm would correspond to an EMF of 0.6 V (60 × 0.01), not 0.4 V. The balancing length for 0.4 V is 40 cm.", "misconception": null}, {"option_key": "C", "hint": "25 cm would correspond to an EMF of 0.25 V. For 0.4 V, l = 0.4/(1/100) = 40 cm.", "misconception": null}, {"option_key": "D", "hint": "4 cm would result from using potential gradient as 0.1 V/cm instead of 0.01 V/cm. k = 1 V / 100 cm = 0.01 V/cm.", "misconception": "Error in calculating the potential gradient"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A galvanometer of resistance 100 Ω gives full-scale deflection at a current of 2 mA. To convert it into an ammeter of range 0–2 A, the shunt resistance required is:", "explanation": "Shunt resistance S = IgG/(I - Ig) = (2 × 10⁻³ × 100)/(2 - 0.002) = 0.2/1.998 ≈ 0.1 Ω. Since I >> Ig, we can approximate S ≈ IgG/I = 0.2/2 = 0.1 Ω. The low shunt resistance ensures most of the current bypasses the galvanometer.", "correct_answer": "D", "concept_tags": ["galvanometer-to-ammeter", "shunt-resistance", "full-scale-deflection"], "payload": {"question_id": "cuet-phy-current-instruments-08", "subtopic": "Electrical Instruments", "topic_name": "Electrical Instruments", "bloom_level": "apply", "options": [{"key": "A", "text": "100 Ω", "is_correct": false}, {"key": "B", "text": "1 Ω", "is_correct": false}, {"key": "C", "text": "0.01 Ω", "is_correct": false}, {"key": "D", "text": "0.1 Ω", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "100 Ω equals the galvanometer resistance and would only divide the current equally. The shunt must be much smaller to carry nearly all of the 2 A.", "misconception": "Thinking shunt should equal galvanometer resistance"}, {"option_key": "B", "hint": "1 Ω would carry about 100/101 of the total current but is 10 times too large. S = 0.002 × 100/2 ≈ 0.1 Ω.", "misconception": null}, {"option_key": "C", "hint": "0.01 Ω is too small. This would convert the galvanometer to a 20 A range ammeter, not 2 A.", "misconception": null}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In a potentiometer experiment, two cells of EMF E₁ and E₂ give balancing lengths l₁ and l₂ respectively. The ratio E₁/E₂ is:", "explanation": "In a potentiometer, at the balance point, E = kl where k is the potential gradient (constant for a given setup). For cell 1: E₁ = kl₁, and for cell 2: E₂ = kl₂. Dividing: E₁/E₂ = l₁/l₂. This is the standard method for comparing EMFs using a potentiometer without drawing any current from the cells.", "correct_answer": "B", "concept_tags": ["potentiometer", "comparison-of-EMFs", "balancing-length"], "payload": {"question_id": "cuet-phy-current-instruments-09", "subtopic": "Electrical Instruments", "topic_name": "Electrical Instruments", "bloom_level": "understand", "options": [{"key": "A", "text": "l₂/l₁", "is_correct": false}, {"key": "B", "text": "l₁/l₂", "is_correct": true}, {"key": "C", "text": "(l₁ + l₂)/(l₁ − l₂)", "is_correct": false}, {"key": "D", "text": "l₁ × l₂", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "l₂/l₁ = E₂/E₁, which is the inverse of what is asked. E₁/E₂ = l₁/l₂, not l₂/l₁.", "misconception": "Inverting the ratio"}, {"option_key": "C", "hint": "(l₁ + l₂)/(l₁ - l₂) is not the correct relation. The comparison formula is simply E₁/E₂ = l₁/l₂.", "misconception": "Confusing with sum-difference formulas used in other experiments"}, {"option_key": "D", "hint": "l₁ × l₂ is a product with units of cm², which cannot equal a dimensionless ratio like E₁/E₂.", "misconception": null}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "An ideal voltmeter has:", "explanation": "An ideal voltmeter should have infinite resistance so that when connected across a circuit element, it draws no current and does not disturb the circuit. This ensures that the voltmeter measures the true potential difference. In practice, voltmeters have very high but finite resistance.", "correct_answer": "C", "concept_tags": ["voltmeter", "ideal-instrument", "resistance", "measurement"], "payload": {"question_id": "cuet-phy-current-instruments-10", "subtopic": "Electrical Instruments", "topic_name": "Electrical Instruments", "bloom_level": "understand", "options": [{"key": "A", "text": "Zero resistance", "is_correct": false}, {"key": "B", "text": "Low resistance", "is_correct": false}, {"key": "C", "text": "Infinite resistance", "is_correct": true}, {"key": "D", "text": "Resistance equal to the circuit resistance", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Zero resistance describes an ideal ammeter, not a voltmeter. A voltmeter with zero resistance would short-circuit the element.", "misconception": "Confusing ideal ammeter and voltmeter characteristics"}, {"option_key": "B", "hint": "Low resistance in a voltmeter would draw significant current, altering the circuit and giving an incorrect reading.", "misconception": null}, {"option_key": "D", "hint": "If the voltmeter resistance equals the circuit resistance, it would draw as much current as the circuit element and significantly disturb the measurement.", "misconception": null}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "In a potentiometer experiment to measure the internal resistance of a cell, the balancing length without any external resistance is l₁ and with an external resistance R in the cell circuit it is l₂. The internal resistance of the cell is:", "explanation": "Without external resistance: E = kl₁. With external resistance R: V = kl₂, where V = ER/(R + r) is the terminal voltage. So E/V = l₁/l₂ = (R + r)/R. Solving: r = R(l₁ - l₂)/l₂. This method gives accurate results because the potentiometer draws no current at balance.", "correct_answer": "A", "concept_tags": ["potentiometer", "internal-resistance", "balancing-length", "cell"], "payload": {"question_id": "cuet-phy-current-instruments-11", "subtopic": "Electrical Instruments", "topic_name": "Electrical Instruments", "bloom_level": "analyze", "options": [{"key": "A", "text": "R(l₁ − l₂)/l₂", "is_correct": true}, {"key": "B", "text": "R(l₁ − l₂)/l₁", "is_correct": false}, {"key": "C", "text": "Rl₂/(l₁ − l₂)", "is_correct": false}, {"key": "D", "text": "R(l₁ + l₂)/l₂", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R(l₁ - l₂)/l₁ incorrectly places l₁ in the denominator. The correct derivation gives l₂ in the denominator: r = R(l₁/l₂ - 1) = R(l₁ - l₂)/l₂.", "misconception": "Swapping l₁ and l₂ in the denominator"}, {"option_key": "C", "hint": "Rl₂/(l₁ - l₂) is the inverse of the correct expression. Since l₁/l₂ = (R + r)/R, solving for r gives r = R(l₁ - l₂)/l₂.", "misconception": "Inverting the expression during derivation"}, {"option_key": "D", "hint": "R(l₁ + l₂)/l₂ uses addition instead of subtraction. The correct formula involves l₁ - l₂ since l₁ > l₂ (EMF > terminal voltage).", "misconception": "Using addition instead of subtraction of balancing lengths"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "In a Wheatstone bridge, P = 100 Ω, Q = 1000 Ω, R = 40 Ω, and S = 400 Ω. If the galvanometer and battery are interchanged, the bridge will:", "explanation": "The balance condition P/Q = R/S gives 100/1000 = 1/10 and 40/400 = 1/10. Since P/Q = R/S, the bridge is balanced. Interchanging the galvanometer and battery does not affect the balance condition of a Wheatstone bridge. The balance depends only on the resistance ratios, which remain unchanged.", "correct_answer": "B", "concept_tags": ["wheatstone-bridge", "balanced-condition", "galvanometer-battery-interchange"], "payload": {"question_id": "cuet-phy-current-instruments-12", "subtopic": "Electrical Instruments", "topic_name": "Electrical Instruments", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Become unbalanced", "is_correct": false}, {"key": "B", "text": "Remain balanced", "is_correct": true}, {"key": "C", "text": "Show reduced sensitivity", "is_correct": false}, {"key": "D", "text": "Require different resistance values for balance", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The balance condition P/Q = R/S depends only on resistance values, not on the positions of galvanometer and battery. Interchanging them does not affect balance.", "misconception": "Thinking the balance depends on the position of the galvanometer"}, {"option_key": "C", "hint": "While sensitivity may change after interchange, the question asks about balance. The bridge remains balanced since P/Q = R/S still holds.", "misconception": "Confusing sensitivity with balance condition"}, {"option_key": "D", "hint": "The balance condition is a property of the four resistances only. No different values are needed since P/Q = R/S = 1/10 remains true.", "misconception": null}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): A potentiometer is preferred over a voltmeter for measuring the EMF of a cell.\nReason (R): A potentiometer draws no current from the cell at the balance point.", "explanation": "Both statements are correct, and R is the correct explanation of A. A voltmeter draws a small current, so it measures terminal voltage (V = E - Ir), not true EMF. A potentiometer, at balance, draws zero current from the cell (null method), so it measures the true EMF. This zero-current condition makes the potentiometer ideal for EMF measurement.", "correct_answer": "A", "concept_tags": ["potentiometer", "voltmeter", "EMF-measurement", "null-method"], "payload": {"question_id": "cuet-phy-current-instruments-13", "subtopic": "Electrical Instruments", "topic_name": "Electrical Instruments", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Drawing no current is exactly why the potentiometer gives true EMF (no Ir drop). This is a direct cause-and-effect, making R the correct explanation of A.", "misconception": "Not recognizing that zero current directly explains the accuracy of EMF measurement"}, {"option_key": "C", "hint": "The reason is correct. At the balance point of a potentiometer, no current flows through the cell being tested, as the galvanometer reads zero.", "misconception": null}, {"option_key": "D", "hint": "The assertion is correct. Potentiometers give more accurate EMF readings than voltmeters because they use a null method.", "misconception": null}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): An ammeter is always connected in series with the circuit element through which current is to be measured.\nReason (R): An ammeter has very high resistance so that it does not alter the current in the circuit.", "explanation": "The assertion is correct: an ammeter must be connected in series so that the same current that flows through the element also flows through the ammeter. However, the reason is incorrect: an ammeter has very LOW resistance (ideally zero), not high resistance. If it had high resistance, it would significantly reduce the current being measured. The low resistance ensures minimal disturbance to the circuit.", "correct_answer": "C", "concept_tags": ["ammeter", "series-connection", "low-resistance", "measurement"], "payload": {"question_id": "cuet-phy-current-instruments-14", "subtopic": "Electrical Instruments", "topic_name": "Electrical Instruments", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": true}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The reason is factually wrong: an ammeter has very LOW resistance, not high resistance. Therefore, A and B are both eliminated.", "misconception": "Thinking ammeters have high resistance"}, {"option_key": "B", "hint": "Since the reason is incorrect (ammeter has low resistance, not high), this option is also wrong.", "misconception": null}, {"option_key": "D", "hint": "The assertion is correct. An ammeter must be in series to measure the current flowing through a component. Series connection ensures the same current passes through both.", "misconception": null}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match the instruments (Column-I) with their key characteristics (Column-II):\n\nColumn-I:\nA. Ammeter\nB. Voltmeter\nC. Potentiometer\nD. Galvanometer\n\nColumn-II:\n1. Measures EMF accurately using null method\n2. Connected in series; has low resistance\n3. Detects small currents; shows deflection\n4. Connected in parallel; has high resistance", "explanation": "An ammeter is connected in series and has low resistance (A→2). A voltmeter is connected in parallel and has high resistance (B→4). A potentiometer uses the null method to measure EMF accurately (C→1). A galvanometer is a sensitive device that detects small currents (D→3).", "correct_answer": "D", "concept_tags": ["ammeter", "voltmeter", "potentiometer", "galvanometer", "characteristics"], "payload": {"question_id": "cuet-phy-current-instruments-15", "subtopic": "Electrical Instruments", "topic_name": "Electrical Instruments", "bloom_level": "understand", "options": [{"key": "A", "text": "A-4, B-2, C-1, D-3", "is_correct": false}, {"key": "B", "text": "A-2, B-4, C-3, D-1", "is_correct": false}, {"key": "C", "text": "A-1, B-3, C-4, D-2", "is_correct": false}, {"key": "D", "text": "A-2, B-4, C-1, D-3", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "This assigns high resistance/parallel (4) to ammeter and low resistance/series (2) to voltmeter, which is exactly reversed.", "misconception": "Swapping ammeter and voltmeter properties"}, {"option_key": "B", "hint": "This assigns galvanometer to null method (1) and potentiometer to detecting small currents (3). The potentiometer uses the null method, not the galvanometer.", "misconception": "Confusing potentiometer and galvanometer functions"}, {"option_key": "C", "hint": "This scrambles all matchings. Ammeter is connected in series (2), not null method (1).", "misconception": null}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match the following potentiometer applications (Column-I) with the relevant formula (Column-II):\n\nColumn-I:\nA. EMF of a cell\nB. Comparison of two EMFs\nC. Internal resistance of a cell\nD. Potential gradient of the wire\n\nColumn-II:\n1. k = V/L (V across wire, L is total length)\n2. E = kl (k = potential gradient, l = balancing length)\n3. r = R(l₁ − l₂)/l₂\n4. E₁/E₂ = l₁/l₂", "explanation": "EMF of a cell is found using E = kl (A→2). Comparison of EMFs uses E₁/E₂ = l₁/l₂ (B→4). Internal resistance of a cell is given by r = R(l₁ - l₂)/l₂ (C→3). Potential gradient is k = V/L (D→1). These are the fundamental formulas for all standard potentiometer experiments.", "correct_answer": "B", "concept_tags": ["potentiometer", "EMF", "internal-resistance", "potential-gradient", "comparison"], "payload": {"question_id": "cuet-phy-current-instruments-16", "subtopic": "Electrical Instruments", "topic_name": "Electrical Instruments", "bloom_level": "analyze", "options": [{"key": "A", "text": "A-1, B-4, C-3, D-2", "is_correct": false}, {"key": "B", "text": "A-2, B-4, C-3, D-1", "is_correct": true}, {"key": "C", "text": "A-4, B-2, C-1, D-3", "is_correct": false}, {"key": "D", "text": "A-3, B-1, C-2, D-4", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This assigns the potential gradient formula (k = V/L) to EMF measurement, but EMF is found using E = kl (2), not k = V/L (1).", "misconception": "Confusing the potential gradient formula with the EMF measurement formula"}, {"option_key": "C", "hint": "This assigns E₁/E₂ = l₁/l₂ to EMF of a single cell, but that formula is for comparing two EMFs, not measuring one.", "misconception": null}, {"option_key": "D", "hint": "This completely scrambles the matchings, assigning the internal resistance formula to EMF measurement and vice versa.", "misconception": null}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "A metre bridge is a practical form of the Wheatstone bridge.", "explanation": "This statement is TRUE. A metre bridge (also called a slide-wire bridge) is a practical implementation of the Wheatstone bridge. It uses a 1-metre uniform resistance wire to form two arms of the bridge, and the jockey can be slid along the wire to find the balance point. The ratio of wire lengths gives the ratio of resistances.", "correct_answer": "A", "concept_tags": ["metre-bridge", "wheatstone-bridge", "practical-form"], "payload": {"question_id": "cuet-phy-current-instruments-17", "subtopic": "Electrical Instruments", "topic_name": "Electrical Instruments", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "A metre bridge is indeed a practical form of the Wheatstone bridge. It uses the same balance condition (P/Q = R/S) with a uniform wire replacing two resistance arms.", "misconception": "Not recognizing that the metre bridge is based on Wheatstone bridge principle"}, {"option_key": "C", "hint": "This option is not applicable for this question type.", "misconception": null}, {"option_key": "D", "hint": "This option is not applicable for this question type.", "misconception": null}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "A voltmeter should be connected in series with the circuit element to measure the potential difference across it.", "explanation": "This statement is FALSE. A voltmeter must be connected in parallel (not series) with the circuit element across which the potential difference is to be measured. Parallel connection ensures the voltmeter measures the same potential difference as the element. If connected in series, it would measure something entirely different and disrupt the circuit.", "correct_answer": "B", "concept_tags": ["voltmeter", "parallel-connection", "measurement", "potential-difference"], "payload": {"question_id": "cuet-phy-current-instruments-18", "subtopic": "Electrical Instruments", "topic_name": "Electrical Instruments", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "A voltmeter is always connected in parallel, not series. Series connection is for an ammeter. A voltmeter in series would have very high resistance and nearly stop the current.", "misconception": "Confusing voltmeter (parallel) and ammeter (series) connections"}, {"option_key": "C", "hint": "This option is not applicable for this question type.", "misconception": null}, {"option_key": "D", "hint": "This option is not applicable for this question type.", "misconception": null}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "The sensitivity of a potentiometer can be increased by _____ the length of the potentiometer wire.", "explanation": "The sensitivity of a potentiometer is increased by increasing the length of the wire. A longer wire means a smaller potential gradient (k = V/L), so a given EMF corresponds to a larger balancing length. This larger balancing length can be measured more precisely, improving the sensitivity of the measurement. Hence, longer wires allow detection of smaller differences in EMF.", "correct_answer": "C", "concept_tags": ["potentiometer", "sensitivity", "wire-length", "potential-gradient"], "payload": {"question_id": "cuet-phy-current-instruments-19", "subtopic": "Electrical Instruments", "topic_name": "Electrical Instruments", "bloom_level": "understand", "options": [{"key": "A", "text": "Decreasing", "is_correct": false}, {"key": "B", "text": "Halving", "is_correct": false}, {"key": "C", "text": "Increasing", "is_correct": true}, {"key": "D", "text": "Not changing", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Decreasing the wire length increases the potential gradient, which reduces the balancing length and makes it harder to measure precisely, thus decreasing sensitivity.", "misconception": "Thinking shorter wire improves sensitivity"}, {"option_key": "B", "hint": "Halving the wire length would double the potential gradient and reduce sensitivity, not increase it.", "misconception": null}, {"option_key": "D", "hint": "If the length is unchanged, the sensitivity remains the same. To improve sensitivity, the length must be increased.", "misconception": null}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "medium", "question_text": "A student uses a metre bridge to find an unknown resistance X. She places a standard resistance of 10 Ω in the right gap and the unknown resistance X in the left gap. The balance point is obtained at the 33.3 cm mark from the left end. She then swaps the resistances (X in right gap, 10 Ω in left gap) and finds the new balance point.\n\nWhere will the new balance point be located?", "explanation": "First measurement: X/10 = 33.3/(100 - 33.3) = 33.3/66.7 ≈ 1/2, so X ≈ 5 Ω. When resistances are swapped: 10/5 = l/(100 - l), giving 2(100 - l) = l, so 200 = 3l, hence l = 66.7 cm from the left end. Swapping the resistances causes the balance point to shift to the complementary position (100 - 33.3 = 66.7 cm).", "correct_answer": "D", "concept_tags": ["metre-bridge", "balance-point", "swapping-resistances", "unknown-resistance"], "payload": {"question_id": "cuet-phy-current-instruments-20", "subtopic": "Electrical Instruments", "topic_name": "Electrical Instruments", "bloom_level": "apply", "options": [{"key": "A", "text": "33.3 cm from the left end", "is_correct": false}, {"key": "B", "text": "50 cm from the left end", "is_correct": false}, {"key": "C", "text": "25 cm from the left end", "is_correct": false}, {"key": "D", "text": "66.7 cm from the left end", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "33.3 cm was the original balance point. When resistances are swapped, the ratio inverts, and the balance point shifts to the complementary position at 66.7 cm.", "misconception": "Thinking swapping resistances does not change the balance point"}, {"option_key": "B", "hint": "50 cm would be the balance point only if both resistances were equal. Here X ≈ 5 Ω and R = 10 Ω, so they are unequal.", "misconception": "Assuming the balance point always moves to the midpoint"}, {"option_key": "C", "hint": "25 cm does not satisfy the balance condition for the swapped configuration. The new balance length = 100 - 33.3 = 66.7 cm.", "misconception": null}]}}]'::jsonb, 'deploy-2026-03-05-b10');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-dual-nature", "topic_id": "cuet-phy-dual-debroglie", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The de Broglie wavelength associated with a particle of mass m moving with velocity v is given by:", "explanation": "According to de Broglie''s hypothesis, every moving particle has an associated wave whose wavelength is given by λ = h/p = h/(mv), where h is Planck''s constant, m is the mass, and v is the velocity of the particle. This relation connects the wave and particle properties of matter.", "correct_answer": "A", "concept_tags": ["de-broglie-wavelength", "matter-waves", "wave-particle-duality"], "payload": {"question_id": "cuet-phy-dual-debroglie-01", "subtopic": "de Broglie Wavelength", "topic_name": "de Broglie Wavelength", "bloom_level": "remember", "options": [{"key": "A", "text": "h/(mv)", "is_correct": true}, {"key": "B", "text": "hv/m", "is_correct": false}, {"key": "C", "text": "mh/v", "is_correct": false}, {"key": "D", "text": "mv/h", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This expression has dimensions of J·s·(m/s)/kg = m³/s², which is not the dimension of wavelength (m).", "misconception": "Incorrectly rearranging the de Broglie relation"}, {"option_key": "C", "hint": "Dimensionally mh/v gives kg·J·s/(m/s) = kg²·m, which is not a length unit.", "misconception": "Confusing which quantities appear in numerator and denominator"}, {"option_key": "D", "hint": "mv/h is the reciprocal of the correct answer. The wavelength is inversely proportional to momentum, not directly proportional.", "misconception": "Inverting the de Broglie formula"}]}}, {"chapter_id": "cuet-phy-dual-nature", "topic_id": "cuet-phy-dual-debroglie", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "In the Davisson-Germer experiment, the wave nature of electrons was confirmed by observing:", "explanation": "The Davisson-Germer experiment directed a beam of electrons at a nickel crystal and observed a strong diffraction peak at a specific angle. This electron diffraction pattern confirmed that electrons exhibit wave-like behaviour, as predicted by de Broglie''s hypothesis. The diffraction pattern could only be explained by treating electrons as waves.", "correct_answer": "C", "concept_tags": ["davisson-germer-experiment", "electron-diffraction", "wave-nature-of-electrons"], "payload": {"question_id": "cuet-phy-dual-debroglie-02", "subtopic": "de Broglie Wavelength", "topic_name": "de Broglie Wavelength", "bloom_level": "remember", "options": [{"key": "A", "text": "Photoelectric emission from the nickel surface", "is_correct": false}, {"key": "B", "text": "Interference of X-rays scattered by electrons", "is_correct": false}, {"key": "C", "text": "Diffraction of electrons by a nickel crystal", "is_correct": true}, {"key": "D", "text": "Compton scattering of electrons", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Photoelectric emission demonstrates the particle nature of light, not the wave nature of electrons.", "misconception": "Confusing photoelectric effect with electron diffraction"}, {"option_key": "B", "hint": "The Davisson-Germer experiment used electrons, not X-rays, as the incident beam on the crystal.", "misconception": "Confusing electron diffraction with X-ray diffraction"}, {"option_key": "D", "hint": "Compton scattering involves photons scattering off electrons and demonstrates the particle nature of electromagnetic radiation, not the wave nature of electrons.", "misconception": "Mixing up Compton effect with Davisson-Germer experiment"}]}}, {"chapter_id": "cuet-phy-dual-nature", "topic_id": "cuet-phy-dual-debroglie", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The de Broglie wavelength of an electron accelerated through a potential difference V (in volts) is approximately:", "explanation": "When an electron is accelerated through a potential difference V, its kinetic energy equals eV. Using λ = h/√(2meV) and substituting the values of h, m, and e, we get λ = 1.227/√V nm. This is a standard result frequently used in NEET problems involving electron de Broglie wavelength.", "correct_answer": "B", "concept_tags": ["de-broglie-wavelength", "accelerating-potential", "electron"], "payload": {"question_id": "cuet-phy-dual-debroglie-03", "subtopic": "de Broglie Wavelength", "topic_name": "de Broglie Wavelength", "bloom_level": "remember", "options": [{"key": "A", "text": "1.227/V nm", "is_correct": false}, {"key": "B", "text": "1.227/√V nm", "is_correct": true}, {"key": "C", "text": "1.227 × √V nm", "is_correct": false}, {"key": "D", "text": "1.227 × V nm", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The wavelength depends on 1/√V, not 1/V, because kinetic energy is proportional to V and λ ∝ 1/√(KE).", "misconception": "Forgetting the square root in the relation between λ and V"}, {"option_key": "C", "hint": "Wavelength decreases with increasing potential difference; this option suggests wavelength increases with V.", "misconception": "Inverting the relationship between λ and V"}, {"option_key": "D", "hint": "This would mean wavelength increases with voltage, which contradicts the fact that higher voltage gives higher momentum and shorter wavelength.", "misconception": "Completely reversing the proportionality"}]}}, {"chapter_id": "cuet-phy-dual-nature", "topic_id": "cuet-phy-dual-debroglie", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Which of the following has the largest de Broglie wavelength if all are moving with the same velocity?", "explanation": "The de Broglie wavelength is given by λ = h/(mv). For the same velocity, the particle with the smallest mass will have the largest de Broglie wavelength. Among the given options, an electron has the smallest mass (9.1 × 10⁻³¹ kg), which is much less than a proton (1.67 × 10⁻²⁷ kg), a neutron (1.67 × 10⁻²⁷ kg), or an alpha particle (6.64 × 10⁻²⁷ kg). Hence the electron has the largest wavelength.", "correct_answer": "D", "concept_tags": ["de-broglie-wavelength", "mass-dependence", "comparison"], "payload": {"question_id": "cuet-phy-dual-debroglie-04", "subtopic": "de Broglie Wavelength", "topic_name": "de Broglie Wavelength", "bloom_level": "understand", "options": [{"key": "A", "text": "Proton", "is_correct": false}, {"key": "B", "text": "Neutron", "is_correct": false}, {"key": "C", "text": "Alpha particle", "is_correct": false}, {"key": "D", "text": "Electron", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "A proton has a mass about 1836 times that of an electron, giving it a much smaller wavelength at the same speed.", "misconception": null}, {"option_key": "B", "hint": "A neutron has nearly the same mass as a proton and is much heavier than an electron.", "misconception": null}, {"option_key": "C", "hint": "An alpha particle has a mass about 4 times that of a proton and roughly 7300 times that of an electron, so its wavelength is the smallest.", "misconception": "Thinking heavier particles have longer wavelengths"}]}}, {"chapter_id": "cuet-phy-dual-nature", "topic_id": "cuet-phy-dual-debroglie", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "An electron and a proton are accelerated through the same potential difference. The ratio of their de Broglie wavelengths (λ_e/λ_p) is:", "explanation": "When a charged particle is accelerated through potential difference V, its KE = qV. Since both electron and proton have the same charge magnitude, KE_e = KE_p = eV. Using λ = h/√(2mKE), the ratio λ_e/λ_p = √(m_p/m_e). Since m_p/m_e ≈ 1836, λ_e/λ_p = √1836 ≈ 42.8. The electron has a much larger wavelength because of its smaller mass.", "correct_answer": "A", "concept_tags": ["de-broglie-wavelength", "electron-proton-comparison", "accelerating-potential"], "payload": {"question_id": "cuet-phy-dual-debroglie-05", "subtopic": "de Broglie Wavelength", "topic_name": "de Broglie Wavelength", "bloom_level": "apply", "options": [{"key": "A", "text": "√(m_p/m_e)", "is_correct": true}, {"key": "B", "text": "√(m_e/m_p)", "is_correct": false}, {"key": "C", "text": "m_p/m_e", "is_correct": false}, {"key": "D", "text": "m_e/m_p", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This would give a ratio less than 1, meaning the electron has a shorter wavelength than the proton, which contradicts the fact that lighter particles have longer wavelengths at same KE.", "misconception": "Inverting the mass ratio in the wavelength formula"}, {"option_key": "C", "hint": "The ratio involves the square root of the mass ratio because λ ∝ 1/√m at constant kinetic energy, not 1/m.", "misconception": "Forgetting the square root dependence"}, {"option_key": "D", "hint": "This gives a very small number, implying the electron wavelength is negligible compared to the proton''s, which is the opposite of reality.", "misconception": "Confusing which mass goes in the numerator"}]}}, {"chapter_id": "cuet-phy-dual-nature", "topic_id": "cuet-phy-dual-debroglie", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The de Broglie wavelength of an electron accelerated through a potential difference of 100 V is approximately:", "explanation": "Using the formula λ = 1.227/√V nm, where V = 100 V: λ = 1.227/√100 = 1.227/10 = 0.1227 nm ≈ 0.123 nm. This wavelength is comparable to inter-atomic distances, which is why electron beams can be diffracted by crystals.", "correct_answer": "B", "concept_tags": ["de-broglie-wavelength", "numerical-calculation", "accelerating-potential"], "payload": {"question_id": "cuet-phy-dual-debroglie-06", "subtopic": "de Broglie Wavelength", "topic_name": "de Broglie Wavelength", "bloom_level": "apply", "options": [{"key": "A", "text": "0.0123 nm", "is_correct": false}, {"key": "B", "text": "0.123 nm", "is_correct": true}, {"key": "C", "text": "1.23 nm", "is_correct": false}, {"key": "D", "text": "12.3 nm", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This corresponds to V = 10000 V. For V = 100 V, the wavelength is larger since λ ∝ 1/√V.", "misconception": "Using V instead of √V in the calculation"}, {"option_key": "C", "hint": "This would correspond to V = 1 V. Check: 1.227/√1 = 1.227 nm ≈ 1.23 nm. For V = 100 V, the wavelength is 10 times smaller.", "misconception": "Not taking the square root of V"}, {"option_key": "D", "hint": "This value is far too large for an electron accelerated through 100 V. Such a long wavelength would correspond to an extremely low voltage.", "misconception": "Order of magnitude error in calculation"}]}}, {"chapter_id": "cuet-phy-dual-nature", "topic_id": "cuet-phy-dual-debroglie", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "If the kinetic energy of a particle is doubled, its de Broglie wavelength becomes:", "explanation": "The de Broglie wavelength is λ = h/√(2mKE). If KE is doubled, λ'' = h/√(2m × 2KE) = h/(√2 × √(2mKE)) = λ/√2. Therefore, the wavelength becomes 1/√2 times the original wavelength.", "correct_answer": "C", "concept_tags": ["de-broglie-wavelength", "kinetic-energy", "proportionality"], "payload": {"question_id": "cuet-phy-dual-debroglie-07", "subtopic": "de Broglie Wavelength", "topic_name": "de Broglie Wavelength", "bloom_level": "apply", "options": [{"key": "A", "text": "Doubled", "is_correct": false}, {"key": "B", "text": "Halved", "is_correct": false}, {"key": "C", "text": "1/√2 times", "is_correct": true}, {"key": "D", "text": "√2 times", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Wavelength is inversely related to momentum. Doubling KE increases momentum, so wavelength must decrease, not double.", "misconception": "Thinking wavelength is directly proportional to kinetic energy"}, {"option_key": "B", "hint": "Halving would require KE to be quadrupled, not doubled, since λ ∝ 1/√(KE).", "misconception": "Assuming λ ∝ 1/KE instead of λ ∝ 1/√(KE)"}, {"option_key": "D", "hint": "This would mean wavelength increases when KE increases, contradicting the inverse relationship λ ∝ 1/√(KE).", "misconception": "Reversing the relationship between wavelength and kinetic energy"}]}}, {"chapter_id": "cuet-phy-dual-nature", "topic_id": "cuet-phy-dual-debroglie", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The de Broglie wavelength associated with a gas molecule of mass m at temperature T is given by (k is Boltzmann constant):", "explanation": "For a gas molecule at temperature T, the average kinetic energy is (3/2)kT. Using the de Broglie relation λ = h/√(2mKE) = h/√(2m × (3/2)kT) = h/√(3mkT). This expression connects the thermal energy of gas molecules with their wave-like properties.", "correct_answer": "D", "concept_tags": ["de-broglie-wavelength", "thermal-wavelength", "kinetic-theory"], "payload": {"question_id": "cuet-phy-dual-debroglie-08", "subtopic": "de Broglie Wavelength", "topic_name": "de Broglie Wavelength", "bloom_level": "apply", "options": [{"key": "A", "text": "h/√(2mkT)", "is_correct": false}, {"key": "B", "text": "h/√(mkT)", "is_correct": false}, {"key": "C", "text": "h × √(3mkT)", "is_correct": false}, {"key": "D", "text": "h/√(3mkT)", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "This expression uses KE = kT instead of (3/2)kT. The factor of 3 in the denominator comes from using the correct average KE of a gas molecule.", "misconception": "Using KE = kT instead of (3/2)kT for average kinetic energy"}, {"option_key": "B", "hint": "This formula omits the factor of 3 from the average kinetic energy (3/2)kT and also misses the factor of 2 from the momentum-energy relation.", "misconception": "Incorrect substitution of kinetic energy in the de Broglie formula"}, {"option_key": "C", "hint": "Planck''s constant must be divided by the square root term, not multiplied. Wavelength decreases with increasing temperature.", "misconception": "Inverting the de Broglie relation"}]}}, {"chapter_id": "cuet-phy-dual-nature", "topic_id": "cuet-phy-dual-debroglie", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In the Davisson-Germer experiment, the maximum intensity of diffracted electrons was observed at an accelerating voltage of 54 V and a scattering angle of 50°. The experimental de Broglie wavelength of the electron is closest to:", "explanation": "Using the formula λ = 1.227/√V nm: λ = 1.227/√54 = 1.227/7.35 ≈ 0.167 nm = 1.67 Å. This value agreed closely with the wavelength calculated from the Bragg diffraction condition using the known lattice spacing of nickel crystal (d = 0.91 Å), providing strong confirmation of de Broglie''s hypothesis.", "correct_answer": "C", "concept_tags": ["davisson-germer-experiment", "de-broglie-wavelength", "numerical-calculation"], "payload": {"question_id": "cuet-phy-dual-debroglie-09", "subtopic": "de Broglie Wavelength", "topic_name": "de Broglie Wavelength", "bloom_level": "apply", "options": [{"key": "A", "text": "0.567 Å", "is_correct": false}, {"key": "B", "text": "1.00 Å", "is_correct": false}, {"key": "C", "text": "1.67 Å", "is_correct": true}, {"key": "D", "text": "2.67 Å", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This value is too small. It would correspond to an accelerating voltage of about 467 V, not 54 V.", "misconception": "Calculation error in applying the formula"}, {"option_key": "B", "hint": "λ = 1.227/√54 ≈ 1.227/7.35 ≈ 0.167 nm = 1.67 Å, not 1.00 Å.", "misconception": "Rounding errors or incorrect square root calculation"}, {"option_key": "D", "hint": "This would correspond to √V ≈ 4.6, i.e., V ≈ 21 V, which is not the 54 V used in the experiment.", "misconception": "Arithmetic error in division"}]}}, {"chapter_id": "cuet-phy-dual-nature", "topic_id": "cuet-phy-dual-debroglie", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "An electron and a photon have the same de Broglie wavelength λ. If p_e and p_ph denote their momenta and E_e and E_ph denote their energies respectively, then which of the following is correct?", "explanation": "Since both have the same wavelength λ, their momenta are equal: p_e = p_ph = h/λ. For the electron, E_e = p²/(2m_e). For the photon, E_ph = pc = hc/λ. Since p_e = p_ph, but their energy-momentum relations differ (E = p²/2m for electron vs E = pc for photon), their energies are different. Specifically, E_e/E_ph = p/(2m_e c), which is less than 1 for typical wavelengths, so E_e < E_ph.", "correct_answer": "A", "concept_tags": ["photon-vs-matter-wave", "momentum", "energy-comparison"], "payload": {"question_id": "cuet-phy-dual-debroglie-10", "subtopic": "de Broglie Wavelength", "topic_name": "de Broglie Wavelength", "bloom_level": "analyze", "options": [{"key": "A", "text": "p_e = p_ph but E_e ≠ E_ph", "is_correct": true}, {"key": "B", "text": "p_e ≠ p_ph but E_e = E_ph", "is_correct": false}, {"key": "C", "text": "p_e = p_ph and E_e = E_ph", "is_correct": false}, {"key": "D", "text": "p_e/p_ph = E_e/E_ph", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Since both have the same wavelength, by p = h/λ their momenta must be equal. Their energies differ because the energy-momentum relation is different for massive and massless particles.", "misconception": "Thinking that same wavelength means same energy"}, {"option_key": "C", "hint": "While momenta are equal (both given by h/λ), the energy of an electron is p²/(2m) while that of a photon is pc. These are not the same.", "misconception": "Assuming identical wave properties imply identical particle properties"}, {"option_key": "D", "hint": "Since p_e = p_ph, the ratio p_e/p_ph = 1. But E_e/E_ph = p/(2m_e c) ≠ 1 in general.", "misconception": "Assuming proportionality between momentum ratio and energy ratio"}]}}, {"chapter_id": "cuet-phy-dual-nature", "topic_id": "cuet-phy-dual-debroglie", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A proton and an alpha particle are accelerated through the same potential difference. The ratio of the de Broglie wavelengths associated with the proton to the alpha particle (λ_p/λ_α) is:", "explanation": "For a charged particle accelerated through potential difference V, KE = qV. So λ = h/√(2m·qV). For a proton: mass = m, charge = e. For an alpha particle: mass = 4m, charge = 2e. Therefore λ_p/λ_α = √(m_α × q_α)/(m_p × q_p)) = √((4m × 2e)/(m × e)) = √8 = 2√2.", "correct_answer": "D", "concept_tags": ["de-broglie-wavelength", "proton-alpha-comparison", "accelerating-potential"], "payload": {"question_id": "cuet-phy-dual-debroglie-11", "subtopic": "de Broglie Wavelength", "topic_name": "de Broglie Wavelength", "bloom_level": "analyze", "options": [{"key": "A", "text": "1 : 2", "is_correct": false}, {"key": "B", "text": "2 : 1", "is_correct": false}, {"key": "C", "text": "1 : 2√2", "is_correct": false}, {"key": "D", "text": "2√2 : 1", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "This ignores the charge difference. The alpha particle has charge 2e and mass 4m. Both must be accounted for in the KE = qV relation.", "misconception": "Only considering mass ratio and ignoring charge"}, {"option_key": "B", "hint": "The ratio should account for both mass and charge differences. λ ∝ 1/√(mq), so the lighter particle with smaller charge has a longer wavelength.", "misconception": "Partially correct reasoning but missing charge factor"}, {"option_key": "C", "hint": "This is the inverse of the correct ratio. The proton, being lighter and having smaller charge, has the longer wavelength.", "misconception": "Inverting the ratio"}]}}, {"chapter_id": "cuet-phy-dual-nature", "topic_id": "cuet-phy-dual-debroglie", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "An electron microscope uses electrons accelerated through a potential of 10000 V. The resolving power of this microscope is high because the de Broglie wavelength of the electrons is approximately:", "explanation": "Using λ = 1.227/√V nm = 1.227/√10000 = 1.227/100 = 0.01227 nm ≈ 0.0123 nm = 0.123 Å. This wavelength is much smaller than that of visible light (400-700 nm), which is why electron microscopes can resolve much finer details than optical microscopes.", "correct_answer": "C", "concept_tags": ["electron-microscope", "de-broglie-wavelength", "resolving-power"], "payload": {"question_id": "cuet-phy-dual-debroglie-12", "subtopic": "de Broglie Wavelength", "topic_name": "de Broglie Wavelength", "bloom_level": "apply", "options": [{"key": "A", "text": "12.3 nm", "is_correct": false}, {"key": "B", "text": "1.23 nm", "is_correct": false}, {"key": "C", "text": "0.0123 nm", "is_correct": true}, {"key": "D", "text": "0.00123 nm", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "12.3 nm corresponds to V ≈ 0.01 V. For V = 10000 V, the wavelength is much smaller.", "misconception": "Forgetting to take the square root of V"}, {"option_key": "B", "hint": "1.23 nm corresponds to V ≈ 1 V. Check: 1.227/√1 = 1.227 nm ≈ 1.23 nm.", "misconception": "Using V = 1 instead of V = 10000"}, {"option_key": "D", "hint": "This would correspond to V ≈ 10⁶ V, which is 100 times the given voltage.", "misconception": "Calculation error with powers of 10"}]}}, {"chapter_id": "cuet-phy-dual-nature", "topic_id": "cuet-phy-dual-debroglie", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): The Davisson-Germer experiment provided direct experimental evidence for the wave nature of electrons.\nReason (R): In this experiment, electrons were diffracted by a nickel crystal, and the measured wavelength agreed with the de Broglie relation λ = h/(mv).", "explanation": "Both the Assertion and Reason are correct. The Davisson-Germer experiment demonstrated electron diffraction from a nickel crystal surface. The wavelength measured from the diffraction pattern (using Bragg''s law) agreed closely with the value predicted by the de Broglie relation, thus confirming the wave nature of electrons. The Reason correctly explains why the Assertion is true.", "correct_answer": "A", "concept_tags": ["davisson-germer-experiment", "wave-nature-of-electrons", "de-broglie-hypothesis"], "payload": {"question_id": "cuet-phy-dual-debroglie-13", "subtopic": "de Broglie Wavelength", "topic_name": "de Broglie Wavelength", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The reason directly explains the assertion — the diffraction of electrons and agreement with de Broglie''s formula is precisely what constituted the evidence for the wave nature of electrons.", "misconception": "Thinking the reason is unrelated to the assertion"}, {"option_key": "C", "hint": "The reason accurately describes what happened in the Davisson-Germer experiment. Electrons were indeed diffracted by nickel crystal, and the wavelength matched de Broglie''s prediction.", "misconception": "Doubting the factual accuracy of the reason"}, {"option_key": "D", "hint": "The assertion is historically and scientifically correct — the Davisson-Germer experiment is the landmark experiment that confirmed electron wave nature.", "misconception": "Questioning the significance of the Davisson-Germer experiment"}]}}, {"chapter_id": "cuet-phy-dual-nature", "topic_id": "cuet-phy-dual-debroglie", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): A heavier particle always has a smaller de Broglie wavelength than a lighter particle.\nReason (R): The de Broglie wavelength is given by λ = h/p, where p is the momentum of the particle.", "explanation": "The Assertion is incorrect. A heavier particle does NOT always have a smaller de Broglie wavelength. The wavelength depends on momentum (p = mv), not mass alone. A heavy particle moving very slowly can have a smaller momentum (and hence larger wavelength) than a light particle moving very fast. The Reason is correct — λ = h/p is the de Broglie relation. However, since the Assertion is wrong, option D applies.", "correct_answer": "D", "concept_tags": ["de-broglie-wavelength", "momentum", "mass-velocity-dependence"], "payload": {"question_id": "cuet-phy-dual-debroglie-14", "subtopic": "de Broglie Wavelength", "topic_name": "de Broglie Wavelength", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "The assertion is not always true. A slow-moving heavy particle can have a larger wavelength than a fast-moving light particle. Wavelength depends on momentum, not mass alone.", "misconception": "Thinking wavelength depends only on mass"}, {"option_key": "B", "hint": "The assertion is incorrect. Consider a heavy particle at rest (λ → ∞) versus a fast-moving light particle (small λ). Mass alone does not determine wavelength.", "misconception": "Partially accepting an incorrect assertion"}, {"option_key": "C", "hint": "The reason λ = h/p is the correct de Broglie relation. It is a fundamental formula in quantum mechanics.", "misconception": "Doubting the de Broglie formula"}]}}, {"chapter_id": "cuet-phy-dual-nature", "topic_id": "cuet-phy-dual-debroglie", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match Column I with Column II:\n\nColumn I:\n(P) de Broglie wavelength in terms of momentum\n(Q) de Broglie wavelength in terms of KE\n(R) de Broglie wavelength of electron (V in volts)\n(S) de Broglie wavelength in terms of temperature\n\nColumn II:\n(1) h/√(3mkT)\n(2) 1.227/√V nm\n(3) h/p\n(4) h/√(2mKE)", "explanation": "P → 3: The fundamental de Broglie relation is λ = h/p. Q → 4: Since p = √(2mKE), λ = h/√(2mKE). R → 2: Substituting electron mass and charge values, λ = 1.227/√V nm. S → 1: Using average KE = (3/2)kT, λ = h/√(3mkT). The correct matching is P-3, Q-4, R-2, S-1.", "correct_answer": "B", "concept_tags": ["de-broglie-wavelength", "formulas", "matching"], "payload": {"question_id": "cuet-phy-dual-debroglie-15", "subtopic": "de Broglie Wavelength", "topic_name": "de Broglie Wavelength", "bloom_level": "understand", "options": [{"key": "A", "text": "P-3, Q-1, R-2, S-4", "is_correct": false}, {"key": "B", "text": "P-3, Q-4, R-2, S-1", "is_correct": true}, {"key": "C", "text": "P-4, Q-3, R-1, S-2", "is_correct": false}, {"key": "D", "text": "P-2, Q-4, R-3, S-1", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This incorrectly matches Q with the temperature formula and S with the KE formula. Q should match with h/√(2mKE) and S with h/√(3mkT).", "misconception": "Swapping kinetic energy and temperature formulae"}, {"option_key": "C", "hint": "P is the most basic form λ = h/p which matches (3), not (4). Also R is the electron-specific formula which matches (2), not (1).", "misconception": "Confusing the basic momentum formula with the KE formula"}, {"option_key": "D", "hint": "P matches the fundamental relation λ = h/p = (3), not the electron-specific formula (2). R is the electron-specific result matching (2), not (3).", "misconception": "Swapping the fundamental and electron-specific formulae"}]}}, {"chapter_id": "cuet-phy-dual-nature", "topic_id": "cuet-phy-dual-debroglie", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match Column I with Column II:\n\nColumn I:\n(P) Davisson-Germer experiment\n(Q) Heisenberg''s uncertainty principle\n(R) Electron microscope\n(S) Photoelectric effect\n\nColumn II:\n(1) Δx · Δp ≥ h/(4π)\n(2) Confirms wave nature of electrons experimentally\n(3) Uses small de Broglie wavelength of electrons for high resolution\n(4) Demonstrates particle nature of light", "explanation": "P → 2: The Davisson-Germer experiment confirmed the wave nature of electrons through electron diffraction by nickel crystal. Q → 1: Heisenberg''s uncertainty principle states Δx · Δp ≥ ℏ/2 = h/(4π). R → 3: Electron microscopes exploit the very small de Broglie wavelength of high-energy electrons to achieve resolution far superior to optical microscopes. S → 4: The photoelectric effect demonstrates the particle nature of light (photons).", "correct_answer": "C", "concept_tags": ["davisson-germer-experiment", "uncertainty-principle", "electron-microscope", "photoelectric-effect"], "payload": {"question_id": "cuet-phy-dual-debroglie-16", "subtopic": "de Broglie Wavelength", "topic_name": "de Broglie Wavelength", "bloom_level": "analyze", "options": [{"key": "A", "text": "P-2, Q-3, R-1, S-4", "is_correct": false}, {"key": "B", "text": "P-4, Q-1, R-3, S-2", "is_correct": false}, {"key": "C", "text": "P-2, Q-1, R-3, S-4", "is_correct": true}, {"key": "D", "text": "P-3, Q-1, R-2, S-4", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This swaps Q and R. The uncertainty principle is Δx · Δp ≥ h/(4π), which is (1), not (3). The electron microscope uses small wavelengths for resolution, which is (3), not (1).", "misconception": "Confusing the uncertainty principle with the electron microscope principle"}, {"option_key": "B", "hint": "The Davisson-Germer experiment confirms wave nature of electrons (2), not particle nature of light (4). The photoelectric effect demonstrates particle nature of light.", "misconception": "Confusing wave nature of electrons with particle nature of light"}, {"option_key": "D", "hint": "P is about electron diffraction confirming wave nature (2), not about using small wavelength for resolution (3). R uses de Broglie wavelength for resolution (3), not confirming wave nature (2).", "misconception": "Swapping the Davisson-Germer experiment with the electron microscope"}]}}, {"chapter_id": "cuet-phy-dual-nature", "topic_id": "cuet-phy-dual-debroglie", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The de Broglie wavelength of a moving particle is inversely proportional to its momentum.", "explanation": "This statement is TRUE. According to the de Broglie relation, λ = h/p, the wavelength is inversely proportional to the momentum p. As the momentum of a particle increases, its associated de Broglie wavelength decreases. This is a direct consequence of de Broglie''s hypothesis connecting wave and particle properties.", "correct_answer": "A", "concept_tags": ["de-broglie-wavelength", "momentum", "inverse-proportionality"], "payload": {"question_id": "cuet-phy-dual-debroglie-17", "subtopic": "de Broglie Wavelength", "topic_name": "de Broglie Wavelength", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The de Broglie relation λ = h/p clearly shows that wavelength and momentum are inversely related. This is a fundamental and correct relationship.", "misconception": "Misunderstanding the de Broglie relation"}, {"option_key": "C", "hint": "This option is not applicable.", "misconception": null}, {"option_key": "D", "hint": "This option is not applicable.", "misconception": null}]}}, {"chapter_id": "cuet-phy-dual-nature", "topic_id": "cuet-phy-dual-debroglie", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The de Broglie wavelength of a cricket ball moving at 30 m/s is easily observable and measurable in daily life.", "explanation": "This statement is FALSE. For a cricket ball (mass ≈ 0.16 kg) moving at 30 m/s, λ = h/(mv) = 6.63 × 10⁻³⁴/(0.16 × 30) ≈ 1.38 × 10⁻³⁴ m. This is an incredibly small wavelength — far smaller than any known physical dimension — and is completely undetectable by any instrument. The wave nature of macroscopic objects is negligible, which is why wave-particle duality is only significant at the atomic and subatomic scale.", "correct_answer": "B", "concept_tags": ["de-broglie-wavelength", "macroscopic-objects", "wave-particle-duality"], "payload": {"question_id": "cuet-phy-dual-debroglie-18", "subtopic": "de Broglie Wavelength", "topic_name": "de Broglie Wavelength", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Calculate: λ = 6.63 × 10⁻³⁴/(0.16 × 30) ≈ 10⁻³⁴ m. This is about 10⁻¹⁹ times smaller than a proton. Such wavelengths cannot be observed.", "misconception": "Thinking wave nature is significant for macroscopic objects"}, {"option_key": "C", "hint": "This option is not applicable.", "misconception": null}, {"option_key": "D", "hint": "This option is not applicable.", "misconception": null}]}}, {"chapter_id": "cuet-phy-dual-nature", "topic_id": "cuet-phy-dual-debroglie", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "According to Heisenberg''s uncertainty principle, the product of the uncertainty in position (Δx) and the uncertainty in momentum (Δp) of a particle is always greater than or equal to _____.", "explanation": "Heisenberg''s uncertainty principle states that Δx · Δp ≥ ℏ/2 = h/(4π), where ℏ = h/(2π) is the reduced Planck constant. This means it is fundamentally impossible to simultaneously measure both the exact position and exact momentum of a particle. The product of their uncertainties has a lower bound of h/(4π) ≈ 5.27 × 10⁻³⁵ J·s.", "correct_answer": "B", "concept_tags": ["heisenberg-uncertainty-principle", "position", "momentum"], "payload": {"question_id": "cuet-phy-dual-debroglie-19", "subtopic": "de Broglie Wavelength", "topic_name": "de Broglie Wavelength", "bloom_level": "remember", "options": [{"key": "A", "text": "h/(2π)", "is_correct": false}, {"key": "B", "text": "h/(4π)", "is_correct": true}, {"key": "C", "text": "h", "is_correct": false}, {"key": "D", "text": "h/(8π)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "h/(2π) is ℏ (h-bar). The uncertainty principle states Δx · Δp ≥ ℏ/2, which equals h/(4π), not h/(2π).", "misconception": "Confusing ℏ with ℏ/2"}, {"option_key": "C", "hint": "Using the full Planck constant h overestimates the minimum uncertainty product by a factor of 4π.", "misconception": "Omitting the 4π factor"}, {"option_key": "D", "hint": "h/(8π) is too small. The correct minimum is h/(4π) = ℏ/2.", "misconception": "Adding an extra factor of 2 in the denominator"}]}}, {"chapter_id": "cuet-phy-dual-nature", "topic_id": "cuet-phy-dual-debroglie", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "medium", "question_text": "A physics laboratory has an electron gun that can accelerate electrons through adjustable potential differences. A researcher needs to study the crystal structure of a sample with inter-atomic spacing of approximately 2.5 Å. For the electrons to be effectively diffracted by this crystal, the de Broglie wavelength of the electrons should be comparable to the inter-atomic spacing. The potential difference through which the electrons should be accelerated is approximately:", "explanation": "For effective diffraction, we need λ ≈ 2.5 Å = 0.25 nm. Using the formula λ = 1.227/√V nm: 0.25 = 1.227/√V, so √V = 1.227/0.25 = 4.908, hence V = (4.908)² ≈ 24.1 V ≈ 24 V. This demonstrates the practical application of the de Broglie wavelength concept — electrons accelerated through modest potential differences have wavelengths comparable to crystal lattice spacings, making them ideal probes for crystal structure analysis.", "correct_answer": "D", "concept_tags": ["de-broglie-wavelength", "electron-diffraction", "crystal-structure", "numerical-calculation"], "payload": {"question_id": "cuet-phy-dual-debroglie-20", "subtopic": "de Broglie Wavelength", "topic_name": "de Broglie Wavelength", "bloom_level": "apply", "options": [{"key": "A", "text": "2.4 V", "is_correct": false}, {"key": "B", "text": "54 V", "is_correct": false}, {"key": "C", "text": "100 V", "is_correct": false}, {"key": "D", "text": "24 V", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "At 2.4 V, λ = 1.227/√2.4 ≈ 0.79 nm = 7.9 Å, which is much larger than the required 2.5 Å.", "misconception": "Confusing V with √V in the formula"}, {"option_key": "B", "hint": "At 54 V, λ = 1.227/√54 ≈ 0.167 nm = 1.67 Å. This is too small compared to the required 2.5 Å spacing.", "misconception": "Remembering the Davisson-Germer voltage without calculating for the given spacing"}, {"option_key": "C", "hint": "At 100 V, λ = 1.227/√100 = 0.123 nm = 1.23 Å, which is about half the required wavelength.", "misconception": "Overestimating the required voltage"}]}}]'::jsonb, 'deploy-2026-03-05-b10');

